head.script:
scwin.wrkLobranCd;	// 작업점소코드
scwin.wrkLobranNm;	// 작업점소명
scwin.internalSellLodeptCd;	// 매출귀속부서코드
scwin.internalSellLodeptNm;	// 매출귀속부서명
scwin.wrkLobranCdRow = 0;	// 작업점소 설정 ROW

scwin.odrNo;	// 오더
scwin.bizDivCntrYn; // 사업부문컨테이너여부
scwin.bizDivBulkYn; // 사업부문벌크여부

scwin.lobranCd;    // 사용자 소속점소코드
scwin.lobranNm;    // 사용자 소속점소명
scwin.userId;

scwin.v_dptWrkPlCd = "";    //기준 작업장코드
scwin.v_bizDomCd = "";  //작업장 사업영역코드

scwin.DMessage = {};
scwin.currentRow = -1;
scwin.columnReadonlyInfo = {
    "dptWrkPlNm": true,
    "selpchItemNm": true,
    "wrkLobranNm": true,
    "internalSellLodeptNm": true,
};

/**
 * event
 * @name onpageload
 * @description
 */
scwin.onpageload = function () {
    let param = $c.data.getParameter();
    //탭 안의 화면이라서 탭화면에서 파라메터를 넘기지 않는다면 파라메터가 없다.
    if (!param) {
        param = {
            odrNo: $p.parent().hid_odrNo?.getValue() ?? "",
            type: $p.parent().hid_chkReterieve?.getValue() ?? "",
        }
    }
    scwin.odrNo = param.odrNo ?? "";  //오더번호
    let type = param.type ?? "";    //type

    scwin.bizDivCntrYn = DsConstants.YN_YES;	// 사업부문컨테이너여부
    scwin.bizDivBulkYn = DsConstants.YN_NO;	// 사업부문벌크여부

    hid_odrNo.setValue(scwin.odrNo);
    hid_chkReterieve.setValue(type);

    //사용자 정보 가져오기
    scwin.lobranCd = $c.data.getMemInfo("lobranCd") ?? "";    // 사용자 소속점소코드
    scwin.lobranNm = $c.data.getMemInfo("lobranNm") ?? "";    // 사용자 소속점소명
    scwin.userId = $c.data.getMemInfo("userId") ?? "";

    scwin.setInternalSellLodeptInfo("", "");

    scwin.wrkLobranCd = scwin.lobranCd;	// 작업점소코드
    scwin.wrkLobranNm = scwin.lobranNm;	// 작업점소명
};

/**
 * event
 * @name onUdcCompleted
 * @description
 */
scwin.onUdcCompleted = async function () {
    let msgIds = ["I0108", "I0109", "I0110", "I0111", "I0112", "I0113", "I0114", "I0115", "I0116"];
    for (let item of msgIds) {
        scwin.DMessage[item] = $c.data.getDMessage("SD", item);
    }
    for (let key in scwin.DMessage) {
        scwin.DMessage[key] = (await scwin.DMessage[key]) ?? "";
    }
    // 초기화
    await scwin.f_defaultValue();
};

/**
 * method
 * @name setInternalSellLodeptInfo
 * @description
 */
scwin.setInternalSellLodeptInfo = function (cd, nm) {
    // 사용자 040239 (채태종) 의 경우 운송 부서를 4A5(인천제강운송)으로 설정
    if (scwin.userId == "040239") {
        scwin.internalSellLodeptCd = "4A5";
        scwin.internalSellLodeptNm = "인천제강운송";
    } else {
        scwin.internalSellLodeptCd = cd;
        scwin.internalSellLodeptNm = nm;
    }
};

/**
 * method
 * @name f_initDsLobranQueryCondition
 * @description 물류점소 운영부서 조회조건
 */
scwin.f_initDsLobranQueryCondition = function () {
    dma_lobranQueryCondition.setJSON({
        "lobranCd": scwin.lobranCd,
        "lobranClsCd": "T",
        "deptmentCd": DsConstants.TRANS_DEPARTMENT,
        "useYn": DsConstants.YN_YES,
    });
};

/**
 * method
 * @name f_setTabOrderInfo
 * @description Tab 페이지의 오더 정보를 설정 한다.
 */
scwin.f_setTabOrderInfo = function (odrNo) {
    if (typeof $p.parent().hid_odrNo?.setValue === "function") {
        $p.parent().hid_odrNo.setValue(odrNo);
    }
};

/**
 * method
 * @name f_setDisplayOdrKndCd
 * @description 선택된 오더 유형별 화면 설정을 변경한다.
 */
scwin.f_setDisplayOdrKndCd = function (odrKndCd) {
    switch (odrKndCd) {
        case DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR:	// 컨테이너 수출일반 오더
            break;

        case DsConstants.ODR_KND_CD_IMP_STV_CNTR_ODR:	// 컨테이너 수입하역 오더
        case DsConstants.ODR_KND_CD_EXP_STV_CNTR_ODR:	// 컨테이너 수출하역 오더
            gr_odrCntrWrkPath.setColumnVisible("qty", false);
            gr_odrCntrWrkPath.setColumnVisible("cntrTypCd", false);
            gr_odrCntrWrkPath.setColumnVisible("arvWrkPlNm", false);
            break;

        default:
            /**
            * 기타 컨테이너 오더
            *
            * ODR_KND_CD_IMP_CVSSL_CNTR_ODR = "C1";	// 컨테이너 수입본선 오더
            * ODR_KND_CD_IMP_GNRL_CNTR_ODR = "C2";	// 컨테이너 수입일반 오더
            * ODR_KND_CD_EXP_CVSSL_CNTR_ODR = "C3";	// 컨테이너 수출본선 오더
            * ODR_KND_CD_ON_HIRE_ODR = "C5";	// ON-HIRE 오더
            * ODR_KND_CD_OFF_HIRE_ODR = "C6";	// OFF-HIRE 오더
            * ODR_KND_CD_EMPTY_POSITION_ODR = "C7";	// EMPTY POSITION 오더
            * ODR_KND_CD_CFS_SHUTTLE_ODR = "CF";	// CFS 셔틀 오더
            * ODR_KND_CD_CUSTOM_INSPECTION_ODR = "CI";	// 새관검사 오더
            * ODR_KND_CD_CFS_WORK_ODR = "CJ";	// CFS 작업 오더
            * ODR_KND_CD_OWHOUSE_WORK_ODR = "CK";	// 타창고 작업 오더
            * ODR_KND_CD_CNTR_LDULD_ODR = "CL";	// 컨테이너 상하차 오더
            * ODR_KND_CD_CNTR_STORAGE_ODR = "CM";	// 컨테이너 보관 오더
            * ODR_KND_CD_CNTR_CARGO_SHIFTING_ODR = "CN";	// 컨테이너 이적 오더
            * ODR_KND_CD_PORT_CHANGE_ODR = "CP";	// PORT CHANGE
            * ODR_KND_CD_FIXG_ODR = "CQ";	// 고박
            * ODR_KND_CD_RETURN_ODR = "CR";	// RETURN
            * ODR_KND_CD_CYTS_ODR = "CS";	// 하선지 경우 T/S
            * ODR_KND_CD_TS_ODR = "CT";	// 부두간 T/S
            * ODR_KND_CD_EXAMINE_ODR = "CX";	// 검색기 : EXAMINE
            **/

            gr_odrCntrWrkPath.setColumnVisible("qty", false);
            gr_odrCntrWrkPath.setColumnVisible("cntrTypCd", true);
            gr_odrCntrWrkPath.setColumnVisible("arvWrkPlNm", true);
            // 그리드 항목 설정
            break;
    }
};

/**
 * method
 * @name f_defaultValue
 * @description 초기값 설정
 */
scwin.f_defaultValue = async function () {
    scwin.f_initDsLobranQueryCondition();

    // KeyData 비활성화
    $c.gus.cfDisableKeyData();

    // 그리드 행추가 / 삭제 /취소 버튼 비활성화
    $c.gus.cfDisableAllBtn();

    // 조회 DataSet 초기화
    dma_orderSearch.set("odrNo", "");

    tbx_ctrtClntNm.setValue("");	// 계약거래처명 설정
    tbx_ctrtNo.setValue("");	// 계약번호 설정
    tbx_realMchtClntNmLbl.setValue("실화주");
    tbx_realMchtclntNm.setValue("");	// 실화주명 설정
    tbx_odrKndNm.setValue("");	// 오더종류 설정

    hid_ctrtClntNo.setValue("");	// 계약거래처 코드 설정
    hid_ctrtNo.setValue("");	// 계약번호 설정
    hid_realMchtclntNo.setValue("");	// 실화주 코드 설정

    // 로그인 사용자 물류점소 - 운송부서 조회
    dma_lobranQueryCondition.set("deptmentCd", DsConstants.TRANS_DEPARTMENT);	// 운송부서
    $c.sbm.execute(sbm_retrieveLobranTrans);

    gr_odrCntrWrkPath.setReadOnly("grid", false);
    hid_chkUseFilter.setValue("true");

    //컨테이너 Full/Empty
    dma_retrieveCodeCMD.set("grpCd", "OP171");
    await $c.sbm.execute(sbm_retrieveCntrFE);

    // 오더 확정 버튼 보이기
    dscommon.cf_ShowObject([btnConfirmOrder]);

    // 그리드 총건수 초기화
    tbx_totalRows.setValue(ds_odrCntrWrkPath.getRowCount());
    tbx_totalRows2.setValue(ds_odrWrkPathStepDetail.getRowCount());

    // $c.gus.cfSetIMEModeActiveObjects(gr_odrWrkPathStepDetail);

    // 오더 확정 버튼/ 작업일시배분 조회및 수정 버튼 비활성화
    $c.gus.cfDisableObjects([btnConfirmOrder, btnOrderWrkStepDetail, btnDcSc]);

    ed_odrNo.focus();
};

/**
 * method
 * @name f_Retrieve
 * @description 조회
 */
scwin.f_Retrieve = async function () {
    if (await $c.gus.cfValidate([ed_odrNo])) {
        let odrNo = ed_odrNo.getValue().replace(/\s*$/, '');
        scwin.v_dptWrkPlCd = "";
        scwin.v_bizDomCd = "";

        $c.gus.cfDisableKeyData();

        $c.gus.cfDisableAllBtn();
        $c.gus.cfEnableBtnOnly([btnSave]);

        ds_order.removeAll();
        ds_odrCntrSummary.removeAll();
        ds_ctrtWrkPath.removeAll();
        ds_odrWrkPathStep.removeAll();
        ds_odrCntrWrkPath.setEventPause(null, true);
        ds_odrCntrWrkPath.removeAll();
        ds_odrCntrWrkPath.setEventPause(null, false);
        ds_ctrtWrkPathStep.removeAll();
        ds_odrWrkPathStepDetail.removeAll();

        // 그리드 총건수 초기화
        tbx_totalRows.setValue("0");
        tbx_totalRows2.setValue("0");

        $c.gus.cfDisableObjects([btnConfirmOrder, btnOrderWrkStepDetail, btnDcSc]);

        ds_odrWrkPathStepDetail.removeAll();
        ds_odrWrkPathStepDetailTemp.removeAll();

        // 작업장구분 Lokkup DataSet Setting
        dma_retrieveCodeCMD.set("grpCd", "LO121");
        $c.sbm.execute(sbm_retrieveWrkPlClsCd);

        //작업단계 LookUp DataSet Setting
        $c.sbm.execute(sbm_retrieveLkStepNo);

        dma_orderSearch.set("odrNo", odrNo);
        $c.sbm.execute(sbm_retrieve);
    }
};

/**
 * method
 * @name f_FieldClear
 * @description 조회 조건 초기화
 */
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects([ed_odrNo]);
    ed_odrNo.focus();
};

/**
 * method
 * @name f_RetrieveWorkStep
 * @description 선택된 작업경로에 대한 작업 단계 조회
 */
scwin.f_RetrieveWorkStep = async function () {
    if (dma_searchWrkStep.get("ctrtWrkPathSeq") == 0) {
        return;
    }

    // 선택된 작업경로별 작업단계 조회
    let e = await $c.sbm.execute(sbm_searchWorkStep);
    await scwin.sbm_searchWorkStep_submitdone(e);
};

/**
 * method
 * @name f_InsertRow
 * @description 선택된 그리드에 작업단계 삽입 : 첫번째열을 선택한 경우 해당열 아래에 행삽입 후 이전 작업단계 정보 복사
 */
scwin.f_InsertRow = async function () {
    let row = gr_odrWrkPathStepDetail.getFocusedRowIndex();
    let rowObj = ds_odrWrkPathStepDetail.getRowJSON(row);
    let v_tempSeq = $c.num.parseInt($c.num.parseInt(rowObj.odrWrkStpSeq) / 10) * 10;
    if (scwin.f_checkOdrWrkStpSeq(ds_odrWrkPathStepDetail, v_tempSeq)) {
        // 선택된 행 아래에 새로운 행 삽입
        let addRow = scwin.f_CopyDataRow(ds_odrWrkPathStepDetail, row);
        gr_odrWrkPathStepDetail.setFocusedCell(addRow, gr_odrWrkPathStepDetail.getFocusedColumnID() ?? "dptWrkPlNm", false);

        // 작업단계 추가 가능여부 확인 및 행삽입, 행삭제, 취소 버튼 관리
        scwin.f_checkWorkStepEditMode(addRow);
    } else {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_055, new Array("작업단계"));	//작업단계을(를) 확인하여 주십시오
        return;
    }
};

/**
 * method
 * @name f_DeleteRow
 * @description 선택된 그리드에 작업단계 삭제
 */
scwin.f_DeleteRow = function () {
    let row = gr_odrWrkPathStepDetail.getFocusedRowIndex();
    scwin.deleteRow(ds_odrWrkPathStepDetail, row);
    let rowObj = ds_odrWrkPathStepDetail.getRowJSON(row);
    let v_tempSeq = $c.num.parseInt($c.num.parseInt(rowObj.odrWrkStpSeq) / 10) * 10;
    scwin.f_refreshOdrWrkStpSeq(ds_odrWrkPathStepDetail, v_tempSeq);

    // 작업단계 추가 가능여부 확인 및 행삽입, 행삭제, 취소 버튼 관리
    scwin.f_checkWorkStepEditMode(row);
};

/**
 * method
 * @name f_UndoRow
 * @description 선택된 그리드에 작업단계 작업 취소
 */
scwin.f_UndoRow = function () {
    let row = gr_odrWrkPathStepDetail.getFocusedRowIndex();
    scwin.undoRow(ds_odrWrkPathStepDetail, row);
    let rowObj = ds_odrWrkPathStepDetail.getRowJSON(row);
    let v_tempSeq = $c.num.parseInt($c.num.parseInt(rowObj.odrWrkStpSeq) / 10) * 10;
    scwin.f_refreshOdrWrkStpSeq(ds_odrWrkPathStepDetail, v_tempSeq);

    // 작업단계 추가 가능여부 확인 및 행삽입, 행삭제, 취소 버튼 관리
    scwin.f_checkWorkStepEditMode(row);
};

/**
 * method
 * @name f_CopyDataRow
 * @params {Object} dataObject  대상 DataSet
 * @params {Number} sourceRow   원본 Row
 * @description 선택된 DATASET에 ROW 복사
 */
scwin.f_CopyDataRow = function (dataObject, sourceRow) {
    let rowObj = dataObject.getRowJSON(sourceRow);
    let v_odrWrkStpSeq = $c.num.parseInt(rowObj.odrWrkStpSeq);
    rowObj.odrWrkStpSeq = (v_odrWrkStpSeq + 1).toString();

    let colidArr = [
        "wrkPlClsCd",
        "wrkStpCd",
        "dptWrkPlCd",
        "dptWrkPlNm",
        "arvWrkPlCd",
        "arvWrkPlNm",
        "wrkLobranCd",
        "wrkLobranNm",
        "wrkStDt",
        "wrkStHh",
        "wrkEndDt",
        "wrkEndHh",
        "internalSellLodeptCd",
        "internalSellLodeptNm",
        "bizDomCd",
        "completeYn",
    ];
    for (let colid of colidArr) {
        rowObj[colid] = "";
    }
    dataObject.setRowJSON(sourceRow + 1, rowObj);

    let v_tempSeq = $c.num.parseInt(v_odrWrkStpSeq / 10) * 10;
    scwin.f_refreshOdrWrkStpSeq(dataObject, v_tempSeq);
    return sourceRow + 1;
};

/**
 * method
 * @name f_checkOdrWrkStpSeq
 * @description 선택된 DATASET에 오더 작업단계 추가 가능 확인
 */
scwin.f_checkOdrWrkStpSeq = function (dataObject, v_tempSeq) {
    for (let idx = 0; idx < dataObject.getRowCount(); idx++) {
        const odrWrkStpSeq = $c.num.parseInt(dataObject.getCellData(idx, "odrWrkStpSeq"));
        let v_compSeq = odrWrkStpSeq - v_tempSeq;
        if (v_compSeq >= 9 && $c.num.parseInt(odrWrkStpSeq / 10) * 10 == v_tempSeq) {
            return false;
        }
    }
    return true;
};

/**
 * method
 * @name f_refreshOdrWrkStpSeq
 * @description 선택된 DATASET에 오더 작업단계순번 재정의
 */
scwin.f_refreshOdrWrkStpSeq = function (dataObject, v_tempSeq) {
    // 오더작업단계순번 재정의
    for (let idx = 0; idx < dataObject.getRowCount(); idx++) {
        let odrWrkStpSeq = $c.num.parseInt(dataObject.getCellData(idx, "odrWrkStpSeq"));
        let v_compSeq = odrWrkStpSeq - v_tempSeq;
        if (v_compSeq > 0 && v_compSeq < 10) {
            odrWrkStpSeq = $c.num.parseInt(dataObject.getCellData(idx - 1, "odrWrkStpSeq")) + 1;
            dataObject.setCellData(idx, "odrWrkStpSeq", odrWrkStpSeq.toString());
        }
    }
};

/**
 * method
 * @name f_Update
 * @description 수정
 */
scwin.f_Update = function () {
    $c.gus.cfDisableBtnOnly([btnUpdate]);
    $c.gus.cfEnableBtnOnly([btnSave]);

    gr_odrCntrWrkPath.setReadOnly("grid", false);
    scwin.setGrOdrWrkPathStepDetailReadonly(false);

    if (ds_odrWrkPathStep.getRowCount()) {
        // gr_odrWrkPathStepDetail.setColumnReadOnly("selpchItemNm", true); //None	// 매출입항목
        scwin.setGrOdrWrkPathStepDetailColumnReadonly("selpchItemNm", true); //None	// 매출입항목

        $c.gus.cfDisableBtnOnly([btnInsertRow, btnDeleteRow, btnUndoMark]);
    }

    let row = gr_odrWrkPathStepDetail.getFocusedRowIndex();
    gr_odrWrkPathStepDetail.setFocusedCell(row, "dptWrkPlNm", true);

    // 해당 품명의 실적 발생여부를 확인하여 수정 가능 항목을 설정한다.
    // 실적 발생시 수정할 수 없다.
    // 실적 발생여부를 조회하여 수정항목을 설정한다.
    let odrCommWrkPathRow = gr_odrCntrWrkPath.getFocusedRowIndex();
    if (odrCommWrkPathRow >= 0 && btnUpdate.getDisabled()) {
        if (scwin.f_chkResultsConfirmationContainer(odrCommWrkPathRow)) {
            gr_odrCntrWrkPath.setReadOnly("grid", true);
            scwin.setGrOdrWrkPathStepDetailReadonly(true);
            $c.gus.cfDisableBtnOnly([btnInsertRow, btnDeleteRow, btnUndoMark]);
        } else {
            gr_odrCntrWrkPath.setReadOnly("grid", false);
            scwin.setGrOdrWrkPathStepDetailReadonly(false);
            $c.gus.cfEnableBtnOnly([btnInsertRow, btnDeleteRow, btnUndoMark]);
        }
    }

    // 작업단계 추가 가능여부 확인 및 행삽입, 행삭제, 취소 버튼 관리
    scwin.f_checkWorkStepEditMode(row);
};

/**
 * method
 * @name f_Save
 * @description 저장
 */
scwin.f_Save = async function () {
    // 작업단계 정보가 정확하게 설정되었는지 확인
    if (!scwin.f_chkOdrWorkStepCanRowPosChange()) {
        return;
    }
    // 품명별 작업경로를 선택하지 않은 경우 : 첫번째 품명의 작업경로는 반드시 선택되어야 한다.
    if (ds_odrCntrWrkPath.getCellData(0, "ctrtWrkPathSeq") <= 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_007, new Array("작업경로"));	//작업경로을(를) 선택하십시오.
        gr_odrCntrWrkPath.setFocusedCell(0, gr_odrCntrWrkPath.getFocusedColumnIndex() ?? 1, false);
        return;
    }

    // 작업단계 정보 설정확인
    let prevRowObj = null;
    let rowObj = null;
    for (let i = 1; i < ds_odrWrkPathStepDetail.getRowCount(); i++) {
        rowObj = ds_odrWrkPathStepDetail.getRowJSON(i);
        if (rowObj.rowStatus === "D" || rowObj.wrkPlClsCd.trim() != "") {
            // RowStatus 가 Delete 인 경우
            continue;
        }

        prevRowObj = ds_odrWrkPathStepDetail.getRowJSON(i - 1);
        // 작업구분이 지정되지 않은 경우(운송) 이전 단계의 작업장을 출발작업장으로, 다음 단계의 작업장을 도착작업장으로 설정한다.
        // 작업점소가 설정되지 않은 경우 작업점소는 이전 작업단계의 작업 점소를 설정한다.
        // 작업 점소
        if ($c.gus.cfIsNull(rowObj.wrkLobranCd) && rowObj.selpchItemCd != SdConstants.SELPCH_ITEM_CD_NOSELL) {
            ds_odrWrkPathStepDetail.setCellData(i, "wrkLobranCd", prevRowObj.wrkLobranCd);
        }
        if ($c.gus.cfIsNull(rowObj.wrkLobranNm) && rowObj.selpchItemCd != SdConstants.SELPCH_ITEM_CD_NOSELL) {
            ds_odrWrkPathStepDetail.setCellData(i, "wrkLobranNm", prevRowObj.wrkLobranNm);
        }

        // 작업장
        if ($c.gus.cfIsNull(rowObj.dptWrkPlCd)) {
            ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlCd", prevRowObj.dptWrkPlCd);
        }
        if ($c.gus.cfIsNull(rowObj.arvWrkPlCd)) {
            ds_odrWrkPathStepDetail.setCellData(i, "arvWrkPlCd", ds_odrWrkPathStepDetail.getCellData(i + 1, "dptWrkPlCd"));
        }
        if ($c.gus.cfIsNull(rowObj.arvWrkPlNm)) {
            ds_odrWrkPathStepDetail.setCellData(i, "arvWrkPlNm", ds_odrWrkPathStepDetail.getCellData(i + 1, "dptWrkPlNm"));
        }

        // 매출귀속부서
        if ($c.gus.cfIsNull(rowObj.internalSellLodeptCd) && rowObj.selpchItemCd != SdConstants.SELPCH_ITEM_CD_NOSELL) {
            ds_odrWrkPathStepDetail.setCellData(i, "internalSellLodeptCd", prevRowObj.internalSellLodeptCd);
        }
        if ($c.gus.cfIsNull(rowObj.internalSellLodeptNm) && rowObj.selpchItemCd != SdConstants.SELPCH_ITEM_CD_NOSELL && !$c.gus.cfIsNull(prevRowObj.internalSellLodeptNm)) {
            ds_odrWrkPathStepDetail.setCellData(i, "internalSellLodeptNm", prevRowObj.internalSellLodeptNm);
        }
    }

    // 현재 품명의 작업단계 정보의  Vaildation 을 검사한다.
    if (!await $c.gus.cfValidate([gr_odrWrkPathStepDetail])) {
        return;
    }

    // 필수 입력 확인
    for (let idx = 0; idx < ds_odrWrkPathStepDetail.getRowCount(); idx++) {
        rowObj = ds_odrWrkPathStepDetail.getRowJSON(idx);
        if (rowObj.rowStatus == "D") {
            // RowStatus 가 Delete 인 경우
            continue;
        }

        // 작업장 확인 - 작업구분이 운송이 아닌 경우 작업장은 필수 입력 항목입니다.
        if (!$c.gus.cfIsNull(rowObj.wrkPlClsCd.trim()) && $c.gus.cfIsNull(rowObj.dptWrkPlCd.trim())) {

            await $c.gus.cfAlertMsg(MSG_CM_WRN_007, new Array("작업장"));
            gr_odrWrkPathStepDetail.setFocusedCell(idx, "dptWrkPlNm", true);
            return false;
        }

        // 매출입항목이 무매출이 아니경우에는 작업점소, 매출귀속부서는 필수 입력항목입니다.
        if (rowObj.selpchItemCd != SdConstants.SELPCH_ITEM_CD_NOSELL || $c.gus.cfIsNull(rowObj.wrkPlClsCd.trim())) {
            // 작업점소 확인
            if ($c.gus.cfIsNull(rowObj.wrkLobranCd.trim())) {
                await $c.gus.cfAlertMsg(MSG_CM_WRN_007, new Array("작업점소"));
                gr_odrWrkPathStepDetail.setFocusedCell(idx, "wrkLobranNm", true);
                return false;
            }

            //매출귀속부서 확인
            if ($c.gus.cfIsNull(rowObj.internalSellLodeptCd.trim())) {
                await $c.gus.cfAlertMsg(MSG_CM_WRN_007, new Array("매출귀속부서"));
                gr_odrWrkPathStepDetail.setFocusedCell(idx, "internalSellLodeptNm", true);
                return false;
            }
        }
    }

    gr_odrCntrWrkPath.setFocusedCell(0, gr_odrCntrWrkPath.getFocusedColumnIndex() ?? 1, false);

    // 첫번째 품명의 작업단계 정보의  Vaildation 을 검사한다.
    if (!await $c.gus.cfValidate([gr_odrWrkPathStepDetail])) {
        return;
    }

    ds_odrWrkPathStepDetail.setBroadcast(false, false);
    ds_odrCntrWrkPath.setBroadcast(false, false);

    hid_chkUseFilter.setValue("false");
    scwin.setOdrWrkPathStepDetailColumnFilter(true);

    // 첫번째 작업 경로 중 사용하지 않는 작업단계를 삭제한다.
    let odrCntrWrkPath = ds_odrCntrWrkPath.getRowJSON(0);
    for (let j = 0; j < ds_odrWrkPathStepDetail.getRowCount(); j++) {
        rowObj = ds_odrWrkPathStepDetail.getRowJSON(j);
        if (rowObj.odrNo != odrCntrWrkPath.odrNo || rowObj.cntrSeq != odrCntrWrkPath.cntrSeq) {
            continue;
        }
        // 삭제 대상 작업단계를 삭제한다.
        if (rowObj.ctrtWrkPathSeq != odrCntrWrkPath.ctrtWrkPathSeq && rowObj.rowStatus != "D") {
            scwin.deleteRow(ds_odrWrkPathStepDetail, j);
        }
        // 실적이 발생한 작업단계를 제외
        if (!$c.gus.cfIsNull(odrCntrWrkPath.wrkRsltsNo) && rowObj.ctrtWrkPathSeq == odrCntrWrkPath.ctrtWrkPathSeq) {
            scwin.deleteRow(ds_odrWrkPathStepDetail, j);
        }
    }

    hid_chkUseFilter.setValue("true");
    scwin.setOdrWrkPathStepDetailColumnFilter(true);
    ds_odrWrkPathStepDetail.setBroadcast(true, true);
    ds_odrCntrWrkPath.setBroadcast(true, true);

    // 필수 입력사항을 체크
    if (await scwin.f_validChk() && await $c.win.confirm(MSG_CM_CRM_001.replace("%1", "작업단계정보"))) {
        // 작업경로 , 작업단계 정보 저장

        // disable 처리
        $c.gus.cfDisableKeyData();
        $c.gus.cfDisableAllBtn();

        //asis에서 UseChangeInfo=false인데 전체 데이터를 보내도 rowStatus가 "R"이면 데이터가 삭제된다. 저장하기 위해서 별도 처리 추가
        let allData = ds_odrWrkPathStepDetail.getAllJSON();
        ds_odrWrkPathStepDetailSave.setJSON(allData);
        for (let idx = 0; idx < allData.length; ++idx) {
            if (allData[idx].rowStatus == "D") {
                ds_odrWrkPathStepDetailSave.modifyRowStatus(idx, "D");
            } else {
                ds_odrWrkPathStepDetailSave.modifyRowStatus(idx, "U");
            }
        }
        $c.sbm.execute(sbm_save);
    }
};

/**
 * method
 * @name f_validChk
 * @description 저장전 validation check
 */
scwin.f_validChk = async function () {
    //오더품목  필수 입력사항을 체크
    return await $c.gus.cfValidate([gr_odrCntrWrkPath, gr_odrWrkPathStepDetail]);
};

/**
 * method
 * @name f_openCommPopUpGrid
 * @description Gubun Code 에 따른 공통 Popup 을 호출한다.
 */
scwin.f_openCommPopUpGrid = function (disGubun, row, pCode, pName, pClose, pAllSearch) {
    if ($c.gus.cfIsNull(disGubun)) {
        return false;
    }
    // 선언부
    scwin.currentRow = row;
    let pWrkPlClsCd = null;
    switch (disGubun) {
        case 1:
            // 작업점소(물류점소 : 지점[A], 사업소[B]) 팝업
            udc_logisDeptInfo.cfCommonPopUp(scwin.udc_logisDeptInfo_popup_callback1
                , pCode					// 화면에서의 ??? Code Element의	Value
                , pName					// 화면에서의 ??? Name Element의	Value
                , pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                , null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                , null					// Title순서
                , null					// 보여주는 각 컬럼들의 폭
                , null					// 컬럼중에서 숨기는	컬럼 지정
                , "A,B"					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                , null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                , null					// POP-UP뛰을때 우도우의	사용자 정의	높이
                , null					// 윈도우 위치 Y좌표
                , null					// 윈도우 위치 X좌표
                , null					// 중복체크여부	("F")
                , pAllSearch					// 전체검색허용여부	("F")
                , "작업점소,점소코드,점소명"				// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                , "F"
                , null
            );
            break;

        case 2:
            // 작업장 팝업 	- 작업단계별 작업장 팝업
            pWrkPlClsCd = ds_odrWrkPathStepDetail.getCellData(row, "wrkPlClsCd").trim();		// 작업구분코드
            udc_wrkPlInfo.cfCommonPopUp(scwin.udc_wrkPlInfo_popup_callback
                , pCode					// 화면에서의 ??? Code Element의	Value
                , pName					// 화면에서의 ??? Name Element의	Value
                , pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                , null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                , null					// Title순서
                , null					// 보여주는 각 컬럼들의 폭
                , null					// 컬럼중에서 숨기는	컬럼 지정
                , pWrkPlClsCd					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                , null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                , null					// POP-UP뛰을때 우도우의	사용자 정의	높이
                , null					// 윈도우 위치 Y좌표
                , null					// 윈도우 위치 X좌표
                , null					// 중복체크여부	("F")
                , pAllSearch					// 전체검색허용여부	("F")
                , "작업장,작업장코드,작업장명"				// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                , "F"
                , null
            );
            break;

        case 3:
            // 매출귀속 부서 팝업 	: 작업점소(물류점소 : 팀[T]+작업장(J)) 팝업		- 물류점소구분코드 : LO120 - 팀(T), 지점(A), 사업소(B), CY(C), CFS(F), 작업장(J)
            udc_logisDeptInfo.cfCommonPopUp(scwin.udc_logisDeptInfo_popup_callback2
                , pCode					// 화면에서의 ??? Code Element의	Value
                , pName					// 화면에서의 ??? Name Element의	Value
                , pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                , null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                , null					// Title순서
                , null					// 보여주는 각 컬럼들의 폭
                , null					// 컬럼중에서 숨기는	컬럼 지정
                , "T,J,,,,T,1"					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                , null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                , null					// POP-UP뛰을때 우도우의	사용자 정의	높이
                , null					// 윈도우 위치 Y좌표
                , null					// 윈도우 위치 X좌표
                , null					// 중복체크여부	("F")
                , pAllSearch					// 전체검색허용여부	("F")
                , "매출귀속부서,부서코드,부서명"				// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                , "F"
                , null
            );
            break;

        default:
            break;
    }
};

/**
 * method
 * @name udc_logisDeptInfo_popup_callback1
 * @description
 */
scwin.udc_logisDeptInfo_popup_callback1 = function (rtnList) {
    if (rtnList != null) {
        if (rtnList[0].trim() != "N/A") {
            //return value Assign
            ds_odrWrkPathStepDetail.setCellData(scwin.currentRow, "wrkLobranCd", rtnList[0]);	//작업점소코드
            ds_odrWrkPathStepDetail.setCellData(scwin.currentRow, "wrkLobranNm", rtnList[1]);	//작업점소명
        }
    } else {
        ds_odrWrkPathStepDetail.setCellData(scwin.currentRow, "wrkLobranCd", "");	//작업점소코드
        ds_odrWrkPathStepDetail.setCellData(scwin.currentRow, "wrkLobranNm", "");	//작업점소명
    }

    // 자동 설정된 작업단계 정보를 임시 데이터셋에 복사한다.
    scwin.f_copyTempDataSet();
};

/**
 * method
 * @name udc_wrkPlInfo_popup_callback
 * @description
 */
scwin.udc_wrkPlInfo_popup_callback = function (rtnList) {
    let chkValue = false;
    if (rtnList != null) {
        if (rtnList[0].trim() != "N/A") {
            //return value Assign
            ds_odrWrkPathStepDetail.setCellData(scwin.currentRow, "dptWrkPlCd", rtnList[0]);	//작업장 코드
            if (!$c.gus.cfIsNull(rtnList[3])) {
                ds_odrWrkPathStepDetail.setCellData(scwin.currentRow, "bizDomCd", rtnList[3]);	//작업장 사업영역코드
            }
            if (!$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(scwin.currentRow, "wrkPlClsCd").trim())) {	// 운송 단계가 아닌경우 작업장명 설정
                ds_odrWrkPathStepDetail.setCellData(scwin.currentRow, "dptWrkPlNm", rtnList[1]);	//작업장 명
            }
            // 해당 단계의 출발지를 다음 단계의 출발지로 설정 (다음 단계가 운송 단계인 경우)
            if (scwin.currentRow > 0 && scwin.currentRow < ds_odrWrkPathStepDetail.getRowCount() - 1) {
                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(scwin.currentRow + 1, "wrkPlClsCd").trim())
                    && !$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(scwin.currentRow, "dptWrkPlCd"))) {
                    ds_odrWrkPathStepDetail.setCellData(scwin.currentRow + 1, "dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(scwin.currentRow, "dptWrkPlCd"));
                }
            }
        }
        chkValue = true;
    } else {
        ds_odrWrkPathStepDetail.setCellData(scwin.currentRow, "dptWrkPlCd", "");	//작업장 코드
        ds_odrWrkPathStepDetail.setCellData(scwin.currentRow, "dptWrkPlNm", "");	//작업장 명
    }

    // 자동 설정된 작업단계 정보를 임시 데이터셋에 복사한다.
    scwin.f_copyTempDataSet();

    // 작업 단계 정보 재설정
    if (chkValue) {
        scwin.f_setWorkStepInfoRefresh();
    }
};

/**
 * method
 * @name udc_logisDeptInfo_popup_callback2
 * @description
 */
scwin.udc_logisDeptInfo_popup_callback2 = function (rtnList) {
