        ds_odrWrkPathStepDetail.setCellData(scwin.currentRow, "internalSellLodeptCd", "");	//매출귀속 부서코드
        ds_odrWrkPathStepDetail.setCellData(scwin.currentRow, "internalSellLodeptNm", "");	//매출귀속 부서명
    }

    // 자동 설정된 작업단계 정보를 임시 데이터셋에 복사한다.
    scwin.f_copyTempDataSet();
};

/**
 * method
 * @name f_setWorkLobranNoDataAutoClose
 * @params {Number} row             데이터셋의 Row
 * @params {String} pCode           화면에서의 ??? Code Element의	Value
 * @params {String} pName           화면에서의 ??? Name Element의	Value
 * @params {String} pClose          결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
 * @params {String} pAllSearch      전체검색허용여부	("F")
 * @params {String} pDptWrkPlsYn    출발지(작업장) 검색 여부 (T:출발작업장,F:도착작업장)
 * @params {String} pOrgValueCheck  OrgValue 검색 조건 값 확인 (T : OrgValue 확인, F:확인 안함)
 * @params {String} pNoDataCloseTF
 * @params {String} pDptWrkChangeTF
 * @description 작업장 정보를 조회한다.
 */
scwin.f_setWorkLobranNoDataAutoClose = async function (row, pCode, pName, pClose, pAllSearch, pDptWrkPlsYn, pOrgValueCheck, pNoDataCloseTF, pDptWrkChangeTF) {
    // 조회조건이 아닌경우 종료
    if ($c.gus.cfIsNull(pCode) && $c.gus.cfIsNull(pName)) {
        return false;
    }

    let rowObj = ds_odrWrkPathStepDetail.getRowJSON(row);
    // 작업장 팝업 	- 작업단계별 작업장 팝업
    let pWrkPlClsCd = rowObj.wrkPlClsCd.trim();		// 작업구분코드
    if ($c.gus.cfIsNull(pDptWrkChangeTF)) {
        pDptWrkChangeTF = "F";
    }
    let rtnList = await udc_wrkPlInfoNoDataAutoClose.cfCommonPopUpAsync(null
        , pCode					// 화면에서의 ??? Code Element의	Value
        , pName					// 화면에서의 ??? Name Element의	Value
        , pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
        , null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
        , null					// Title순서
        , null					// 보여주는 각 컬럼들의 폭
        , null					// 컬럼중에서 숨기는	컬럼 지정
        , pWrkPlClsCd					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
        , null					// POP-UP뛰을때 원도우의	사용자 정의	폭
        , null					// POP-UP뛰을때 우도우의	사용자 정의	높이
        , null					// 윈도우 위치 Y좌표
        , null					// 윈도우 위치 X좌표
        , null					// 중복체크여부	("F")
        , pAllSearch					// 전체검색허용여부	("F")
        , "작업장,작업장코드,작업장명"				// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
        , pNoDataCloseTF			// Data건수가 0건일때 Window를 뛰우지 않음 리턴 : "N/A" 또는 null
        , null
    );
    if (rtnList != null) {
        if (rtnList[0].trim() != "N/A") {
            //return value Assign
            if (pDptWrkChangeTF == "F") {
                ds_odrWrkPathStepDetail.setCellData(row, "dptWrkPlCd", rtnList[0]);	//작업장 코드
                if (!$c.gus.cfIsNull(rtnList[3])) {
                    ds_odrWrkPathStepDetail.setCellData(row, "bizDomCd", rtnList[3]);	//작업장 사업영역코드
                }
            }
            if (!$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(row, "wrkPlClsCd").trim())) {// 운송 단계가 아닌경우 작업장명 설정
                ds_odrWrkPathStepDetail.setCellData(row, "dptWrkPlNm", rtnList[1]);	//작업장 명
            }
        }
    } else {
        ds_odrWrkPathStepDetail.setCellData(row, "dptWrkPlCd", "");	//작업장 코드
        ds_odrWrkPathStepDetail.setCellData(row, "dptWrkPlNm", "");	//작업장 명
    }
};

/**
 * method
 * @name f_getUpperWorkPlCd
 * @description 해당 작업장의 상위작업장 정보를 조회한다.
 */
scwin.f_getUpperWorkPlCd = async function (pCode) {
    // 작업장 팝업 	- 작업단계별 작업장 팝업
    // 조회조건이 아닌경우 종료
    if ($c.gus.cfIsNull(pCode)) {
        return null;
    }

    let rtnList = await udc_wrkPlInfoNoDataAutoClose.cfCommonPopUpAsync(null
        , "T"					// 화면에서의 ??? Code Element의	Value
        , ""					// 화면에서의 ??? Name Element의	Value
        , "T"					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
        , null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
        , null					// Title순서
        , null					// 보여주는 각 컬럼들의 폭
        , null					// 컬럼중에서 숨기는	컬럼 지정
        , null					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
        , null					// POP-UP뛰을때 원도우의	사용자 정의	폭
        , null					// POP-UP뛰을때 우도우의	사용자 정의	높이
        , null					// 윈도우 위치 Y좌표
        , null					// 윈도우 위치 X좌표
        , null					// 중복체크여부	("F")
        , "F"				// 전체검색허용여부	("F")
        , "작업장,작업장코드,작업장명"				// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
        , "T"			// Data건수가 0건일때 Window를 뛰우지 않음 리턴 : "N/A" 또는 null
        , null
    );

    if (rtnList != null) {
        if (rtnList[0].trim() != "N/A") {
            return rtnList[5];
        }
    } else {
        return null;
    }
};

/**
 * method
 * @name f_setWorkStepInfoRefresh
 * @description
 * 작업단계의 정보가 변경되었을경우
 * - 작업단계의 출발지 정보를 다시 설정한다.
 * - 매출입항목이 무매출이 아닌경우 작업점소, 매출 귀속 부서를 다시 설정한다.
 * - 작업단계별 작업시작일시, 작업완료일시를 설정한다.
 */
scwin.f_setWorkStepInfoRefresh = async function () {
    let v_impExpDomesticClsCd = ds_order.getCellData(0, "impExpDomesticClsCd");	// 수출입내수구분코드 - IMP_EXP_DOMESTIC_CLS_CD
    ds_odrWrkPathStepDetail.setBroadcast(false, false);
    if (v_impExpDomesticClsCd == DsConstants.IMP_CD) {
        // 수입인 경우
        await scwin.f_setWorkStepInfoRefreshForImport(); //f_setWorkStepInfoRefresh함수가 너무 길어서 별도 함수로 빼버림
    } else if (v_impExpDomesticClsCd == DsConstants.EXP_CD) {
        // 수출인 경우
        await scwin.f_setWorkStepInfoRefreshForExport(); //f_setWorkStepInfoRefresh함수가 너무 길어서 별도 함수로 빼버림
    } else {
        let wrkPathInfo = ds_odrCntrWrkPath.getRowJSON(gr_odrCntrWrkPath.getFocusedRowIndex());
        let v_fullEmptyClsCd = wrkPathInfo.fullEmptyClsCd;	// FULLEMPTY구분코드

        // 수입, 수출이 아닌 경우

        // 작업단계의 출발지 / 도착지 정보를 다시 설정한다.
        for (let i = 0; i < ds_odrWrkPathStepDetail.getRowCount(); i++) {
            const wrkPlClsCd = ds_odrWrkPathStepDetail.getCellData(i, "wrkPlClsCd").trim();
            // 해당 오더의 자가구분이 자가반출인 경우 운송 작업단계를 무매출로 설정한다.
            if (ds_order.getCellData(0, "selfClsCd") == DsConstants.SELF_CLS_CD_SELF_CRRYOUT && $c.gus.cfIsNull(wrkPlClsCd)) {
                ds_odrWrkPathStepDetail.setCellData(i, "selpchItemCd", SdConstants.SELPCH_ITEM_CD_NOSELL);	// 매출항목을 무매출로 설정한다.
                ds_odrWrkPathStepDetail.setCellData(i, "selpchItemNm", "무매출");	// 매출항목을 무매출로 설정한다.
            }

            if (ds_odrWrkPathStepDetail.getRowStatus(i) != "D") {	// RowStatus 가 Delete 가 아닌 경우
                if (i == 0) {
                    // 첫번째 작업단계가 운송단계인 경우 다음 단계의 출발지를 도착지로 설정한다.
                    if ($c.gus.cfIsNull(wrkPlClsCd && !$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i + 1, "dptWrkPlCd")))) {
                        ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(i + 1, "dptWrkPlCd"));
                    }
                } else if (i > 0) {
                    // 현단계 출발지, 도착지 정보 설정

                    // 이전 단계의 출발지(운송단계가 아닌경우) 또는 도착지(운송단계인 경우) 정보를 출발지로 설정한다.
                    if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i - 1, "wrkPlClsCd").trim())) {
                        // 이전 단계가 운송단계인 경우
                        if (!$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i - 1, "arvWrkPlCd"))) {
                            ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(i - 1, "arvWrkPlCd"));
                        }
                    } else {
                        // 이전 단계가 운송단계가 아닌경우 - 직반출이 아닌경우
                        if (wrkPathInfo.arvWrkPlClsCd != SdConstants.WRK_PL_CLS_CD_PIER || wrkPathInfo.dptWrkPlCd != wrkPathInfo.arvWrkPlCd) {
                            if (!$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i - 1, "dptWrkPlCd")) && $c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "dptWrkPlCd"))) {
                                ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(i - 1, "dptWrkPlCd"));
                            }
                        }
                    }

                    // 이전 단계와 작업장 구분코드가 동일한 경우
                    if (wrkPlClsCd == ds_odrWrkPathStepDetail.getCellData(i - 1, "wrkPlClsCd").trim()) {
                        // 작업장구분이 동일한 경우 이전 단계의 작업장/작업점소 정보를 설정한다.
                        if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "dptWrkPlCd"))) {
                            ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(i - 1, "dptWrkPlCd"));	// 출발작업장코드
                            ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlNm", ds_odrWrkPathStepDetail.getCellData(i - 1, "dptWrkPlNm"));	// 출발작업장명
                        }
                    } else if ($c.gus.cfIsNull(wrkPlClsCd)) {
                        // 현단계가 운송단계인 경우
                        // 작업장구분이 운송인 경우 이전 단계의 작업장/작업점소 정보를 설정한다.
                        ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(i - 1, "dptWrkPlCd"));	// 출발작업장코드

                        // 다음 단계의 출발지 정보를 도착지로 설정한다.
                        if (i < ds_odrWrkPathStepDetail.getRowCount() - 1) {
                            if (!$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i + 1, "dptWrkPlCd"))) {
                                ds_odrWrkPathStepDetail.setCellData(i, "arvWrkPlCd", ds_odrWrkPathStepDetail.getCellData(i + 1, "dptWrkPlCd"));
                            }
                        }
                    }

                    // 하역 오더의 경우 도착지 정보가 없기 때문에 이전 단계 작업장정보를 단계별 작업장으로 설정한다.
                    if (hid_odrKndCd.getValue() == DsConstants.ODR_KND_CD_IMP_STV_CNTR_ODR) {
                        if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "dptWrkPlCd"))) {
                            ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(i - 1, "dptWrkPlCd"));	// 출발작업장코드
                            ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlNm", ds_odrWrkPathStepDetail.getCellData(i - 1, "dptWrkPlNm"));	// 출발작업장명
                        }
                    }
                }

                if (i == ds_odrWrkPathStepDetail.getRowCount() - 1) {
                    // 마지막 단계의 출발지 설정
                    // 이전 단계의 출발지(운송단계가 아닌경우) 또는 도착지(운송단계인 경우) 정보를 출발지로 설정한다.
                    if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i - 1, "wrkPlClsCd").trim())) {
                        // 이전 단계가 운송단계인 경우
                        if (!$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i - 1, "arvWrkPlCd"))) {
                            ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(i - 1, "arvWrkPlCd"));
                        }
                    } else {
                        // 이전 단계가 운송단계가 아닌경우 - 직반출이 아닌경우
                        if (wrkPathInfo.arvWrkPlClsCd != SdConstants.WRK_PL_CLS_CD_PIER || wrkPathInfo.dptWrkPlCd != wrkPathInfo.arvWrkPlCd) {
                            if (!$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i - 1, "dptWrkPlCd")) && $c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "dptWrkPlCd")))
                                ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(i - 1, "dptWrkPlCd"));
                        }
                    }

                    // 마지막 작업단계가 운송 단계인 경우 현 단계의 출발지를 도착지로 설정한다.
                    if ($c.gus.cfIsNull(wrkPlClsCd)) {
                        ds_odrWrkPathStepDetail.setCellData(i, "arvWrkPlCd", ds_odrWrkPathStepDetail.getCellData(i, "dptWrkPlCd"));
                    }
                    // 하역 오더의 경우 도착지 정보가 없기 때문에 이전 단계 작업장정보를 단계별 작업장으로 설정한다.
                    if (hid_odrKndCd.getValue() == DsConstants.ODR_KND_CD_IMP_STV_CNTR_ODR) {
                        if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "dptWrkPlCd"))) {
                            ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(i - 1, "dptWrkPlCd"));	// 출발작업장코드
                            ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlNm", ds_odrWrkPathStepDetail.getCellData(i - 1, "dptWrkPlNm"));	// 출발작업장명
                        }
                    }
                }

                // 해당 컨테이너의 F/E 정보를 설정한다.
                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "fullEmptyClsCd"))) {
                    ds_odrWrkPathStepDetail.setCellData(i, "fullEmptyClsCd", v_fullEmptyClsCd);
                }
            }

            // 작업점소, 매출귀속부서 설정
            scwin.f_setOdrWorkStepWorkLobranInternalSellLodept(i);
        }

        // 작업 단계를 역순으로 진행하며 동일 작업장 구분코드인 경우 출발작업장 코드를 설정한다.
        for (let j = ds_odrWrkPathStepDetail.getRowCount() - 1; j >= 0; j--) {
            if (ds_odrWrkPathStepDetail.getRowStatus(j) == "D") {
                continue;
            }
            // RowStatus 가 Delete 가 아닌 경우
            const wrkPlClsCd = ds_odrWrkPathStepDetail.getCellData(j, "wrkPlClsCd").trim();
            if (j >= 0 && j < ds_odrWrkPathStepDetail.getRowCount() - 1) {
                // 다음 단계와 작업장 구분코드가 동일한 경우
                if (wrkPlClsCd == ds_odrWrkPathStepDetail.getCellData(j + 1, "wrkPlClsCd").trim()) {
                    // 작업장구분이 동일한 경우 다음 단계의 작업장/작업점소 정보를 설정한다.
                    if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "dptWrkPlCd"))) {
                        ds_odrWrkPathStepDetail.setCellData(j, "dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(j + 1, "dptWrkPlCd"));	// 출발작업장코드
                        ds_odrWrkPathStepDetail.setCellData(j, "dptWrkPlNm", ds_odrWrkPathStepDetail.getCellData(j + 1, "dptWrkPlNm"));	// 출발작업장명
                    }
                }

                // 현 단계가 운송단계인 경우 다음 단계의 출발지 정보를 도착지로 설정한다.
                if ($c.gus.cfIsNull(wrkPlClsCd) && j < ds_odrWrkPathStepDetail.getRowCount() - 1) {
                    ds_odrWrkPathStepDetail.setCellData(j, "dptWrkPlNm", "");
                    ds_odrWrkPathStepDetail.setCellData(j, "arvWrkPlCd", ds_odrWrkPathStepDetail.getCellData(j + 1, "dptWrkPlCd"));
                }
            }

            // 작업점소, 매출귀속부서 설정
            scwin.f_setOdrWorkStepWorkLobranInternalSellLodept(j);
        }
    }

    ds_odrWrkPathStepDetail.setBroadcast(true, true);

    // 자동 설정된 작업단계 정보를 임시 데이터셋에 복사한다.
    scwin.f_copyTempDataSet();
};

/**
 * method
 * @name f_setWorkStepInfoRefreshForImport
 * @description f_setWorkStepInfoRefresh 함수 수입부분
 */
scwin.f_setWorkStepInfoRefreshForImport = async function () {
    let wrkPathInfo = ds_odrCntrWrkPath.getRowJSON(gr_odrCntrWrkPath.getFocusedRowIndex());
    let v_fullEmptyClsCd = wrkPathInfo.fullEmptyClsCd;	// FULLEMPTY구분코드
    let v_arvWrkPlCd = wrkPathInfo.arvWrkPlCd;	// 도착 작업장코드

    let v_cntrFE = DsConstants.CNTR_FULL_EMPTY_CLS_CD_FULL;	// 컨테이너 F/E 기준값 (F)

    // 작업단계의 출발지 / 도착지 정보를 다시 설정한다.
    for (let i = 0; i < ds_odrWrkPathStepDetail.getRowCount(); i++) {
        const wrkPlClsCd = ds_odrWrkPathStepDetail.getCellData(i, "wrkPlClsCd").trim();
        // 해당 오더의 자가구분이 자가반출인 경우 운송 작업단계를 무매출로 설정한다.
        if (ds_order.getCellData(0, "selfClsCd") == DsConstants.SELF_CLS_CD_SELF_CRRYOUT
            && $c.gus.cfIsNull(wrkPlClsCd)) {
            ds_odrWrkPathStepDetail.setCellData(i, "selpchItemCd", SdConstants.SELPCH_ITEM_CD_NOSELL);	// 매출항목을 무매출로 설정한다.
            ds_odrWrkPathStepDetail.setCellData(i, "selpchItemNm", "무매출");	// 매출항목을 무매출로 설정한다.
        }

        if (ds_odrWrkPathStepDetail.getRowStatus(i) != "D") {	// RowStatus 가 Delete 가 아닌 경우
            if (i == 0) {
                // 첫번째 작업단계가 운송단계인 경우 다음 단계의 출발지를 도착지로 설정한다.
                if ($c.gus.cfIsNull(wrkPlClsCd && !$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i + 1, "dptWrkPlCd")))) {
                    ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(i + 1, "dptWrkPlCd"));
                }
            } else {
                // 현단계 출발지, 도착지 정보 설정
                // 이전 단계의 출발지(운송단계가 아닌경우) 또는 도착지(운송단계인 경우) 정보를 출발지로 설정한다.
                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i - 1, "wrkPlClsCd").trim())) {
                    // 이전 단계가 운송단계인 경우
                    if (!$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i - 1, "arvWrkPlCd"))) {
                        ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(i - 1, "arvWrkPlCd"));
                    }
                } else {
                    // 이전 단계가 운송단계가 아닌경우 - 직반출이 아닌경우
                    if (wrkPathInfo.arvWrkPlClsCd != SdConstants.WRK_PL_CLS_CD_PIER || wrkPathInfo.dptWrkPlCd != wrkPathInfo.arvWrkPlCd) {
                        if (!$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i - 1, "dptWrkPlCd")) && $c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "dptWrkPlCd"))) {
                            ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(i - 1, "dptWrkPlCd"));
                        }
                    }
                }

                // 이전 단계와 작업장 구분코드가 동일한 경우
                if (wrkPlClsCd == ds_odrWrkPathStepDetail.getCellData(i - 1, "wrkPlClsCd").trim()) {
                    // 작업장구분이 동일한 경우 이전 단계의 작업장/작업점소 정보를 설정한다.
                    if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "dptWrkPlCd"))) {
                        ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(i - 1, "dptWrkPlCd"));	// 출발작업장코드
                        ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlNm", ds_odrWrkPathStepDetail.getCellData(i - 1, "dptWrkPlNm"));	// 출발작업장명
                    }
                } else if ($c.gus.cfIsNull(wrkPlClsCd)) {
                    // 현단계가 운송단계인 경우
                    // 작업장구분이 운송인 경우 이전 단계의 작업장/작업점소 정보를 설정한다.
                    ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(i - 1, "dptWrkPlCd"));	// 출발작업장코드

                    // 다음 단계의 출발지 정보를 도착지로 설정한다.
                    if (i < ds_odrWrkPathStepDetail.getRowCount() - 1) {
                        if (!$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i + 1, "dptWrkPlCd"))) {
                            ds_odrWrkPathStepDetail.setCellData(i, "arvWrkPlCd", ds_odrWrkPathStepDetail.getCellData(i + 1, "dptWrkPlCd"));
                        }
                    }
                }

                // 하역 오더의 경우 도착지 정보가 없기 때문에 이전 단계 작업장정보를 단계별 작업장으로 설정한다.
                if (hid_odrKndCd.getValue() == DsConstants.ODR_KND_CD_IMP_STV_CNTR_ODR) {
                    if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "dptWrkPlCd"))) {
                        ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(i - 1, "dptWrkPlCd"));	// 출발작업장코드
                        ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlNm", ds_odrWrkPathStepDetail.getCellData(i - 1, "dptWrkPlNm"));	// 출발작업장명
                    }
                }
            }

            if (i == ds_odrWrkPathStepDetail.getRowCount() - 1) {
                // 마지막 단계의 출발지 설정
                // 이전 단계의 출발지(운송단계가 아닌경우) 또는 도착지(운송단계인 경우) 정보를 출발지로 설정한다.
                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i - 1, "wrkPlClsCd").trim())) {
                    // 이전 단계가 운송단계인 경우
                    if (!$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i - 1, "arvWrkPlCd"))) {
                        ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(i - 1, "arvWrkPlCd"));
                    }
                } else {
                    // 이전 단계가 운송단계가 아닌경우 - 직반출이 아닌경우
                    if (wrkPathInfo.arvWrkPlClsCd != SdConstants.WRK_PL_CLS_CD_PIER || wrkPathInfo.dptWrkPlCd != wrkPathInfo.arvWrkPlCd) {
                        if (!$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i - 1, "dptWrkPlCd")) && $c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "dptWrkPlCd"))) {
                            ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(i - 1, "dptWrkPlCd"));
                        }
                    }
                }

                // 마지막 작업단계가 운송 단계인 경우 현 단계의 출발지를 도착지로 설정한다.
                if ($c.gus.cfIsNull(wrkPlClsCd)) {
                    ds_odrWrkPathStepDetail.setCellData(i, "arvWrkPlCd", ds_odrWrkPathStepDetail.getCellData(i, "dptWrkPlCd"));
                }
                // 하역 오더의 경우 도착지 정보가 없기 때문에 이전 단계 작업장정보를 단계별 작업장으로 설정한다.
                if (hid_odrKndCd.getValue() == DsConstants.ODR_KND_CD_IMP_STV_CNTR_ODR) {
                    if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "dptWrkPlCd"))) {
                        ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(i - 1, "dptWrkPlCd"));	// 출발작업장코드
                        ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlNm", ds_odrWrkPathStepDetail.getCellData(i - 1, "dptWrkPlNm"));	// 출발작업장명
                    }
                }

            }

            // 현단계가 운송(셔틀)이고 출발지(R)->도착지(CY), 출발지(CY)->도착지(R) 인경우
            // 철도역의 상위 작업장과 출도착지가 동일한 경우 작업단계 완료여부를 1로 설정한다. 아닌경우는 0으로 설정한다.
            if (ds_odrWrkPathStepDetail.getCellData(i, "wrkStpCd").trim() == DsConstants.WRK_STP_CD_SHUTTLE) {
                let upperWrkPlCd = "";
                if (ds_odrWrkPathStepDetail.getCellData(i - 1, "wrkPlClsCd").trim() == SdConstants.WRK_PL_CLS_CD_RAILSTN) {
                    // 이전 작업단계가 철도역인 경우
                    // 출발지(철도역)의 상위 작업장 정보 조회
                    if (!$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "dptWrkPlCd"))) {
                        upperWrkPlCd = await scwin.f_getUpperWorkPlCd(ds_odrWrkPathStepDetail.getCellData(i, "dptWrkPlCd"));
                    }
                    // 상위 작업장 정보가 존재하는 경우
                    if (!$c.gus.cfIsNull(upperWrkPlCd)) {
                        // 상위 작업장과 도착작업장이 동일한 경우
                        if (upperWrkPlCd == ds_odrWrkPathStepDetail.getCellData(i, "arvWrkPlCd")) {
                            ds_odrWrkPathStepDetail.setCellData(i, "completeYn", DsConstants.YN_YES);
                        } else {
                            ds_odrWrkPathStepDetail.setCellData(i, "completeYn", DsConstants.YN_NO);
                        }
                    } else {
                        ds_odrWrkPathStepDetail.setCellData(i, "completeYn", DsConstants.YN_NO);
                    }
                } else if (ds_odrWrkPathStepDetail.getCellData(i + 1, "wrkPlClsCd").trim() == SdConstants.WRK_PL_CLS_CD_RAILSTN) {
                    // 다음 작업단계가 철도역인 경우
                    // 도착지(철도역)의 상위 작업장 정보 조회
                    if (!$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "arvWrkPlCd"))) {
                        upperWrkPlCd = await scwin.f_getUpperWorkPlCd(ds_odrWrkPathStepDetail.getCellData(i, "arvWrkPlCd"));
                    }
                    // 상위 작업장 정보가 존재하는 경우
                    if (!$c.gus.cfIsNull(upperWrkPlCd)) {
                        // 상위 작업장과 출발작업장이 동일한 경우
                        if (upperWrkPlCd == ds_odrWrkPathStepDetail.getCellData(i, "dptWrkPlCd")) {
                            ds_odrWrkPathStepDetail.setCellData(i, "completeYn", DsConstants.YN_YES);
                        } else {
                            ds_odrWrkPathStepDetail.setCellData(i, "completeYn", DsConstants.YN_NO);
                        }
                    } else {
                        ds_odrWrkPathStepDetail.setCellData(i, "completeYn", DsConstants.YN_NO);
                    }
                }
            }

            // 현단계의 정보를 확인하여 FULL_EMPTY_CLS_CD 설정한다.
            // 수입일반 인경우 도착작업장 이전단계 까지는 F, 도착작업장 이후 단계는 E 로 설정한다.
            // 수입일반 오더가 아닌경우는 해당 컨테이너의 F/E 정보를 설정한다.
            if (hid_odrKndCd.getValue() == DsConstants.ODR_KND_CD_IMP_GNRL_CNTR_ODR) {
                // 현단계가 운송단계인지 확인
                // 운송 단계인 경우 단계의 도착지와 컨테이너의 도착지가 동일한 경우 까지 "F" 설정 , 이후 단계는 "E" 설정
                if (!$c.gus.cfIsNull(wrkPlClsCd)) {
                    // 현단계가 운송이 아닌 경우
                    if (ds_odrWrkPathStepDetail.getCellData(i, "dptWrkPlCd") == v_arvWrkPlCd) {
                        if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "fullEmptyClsCd"))) {
                            ds_odrWrkPathStepDetail.setCellData(i, "fullEmptyClsCd", v_cntrFE);
                        }
                        v_cntrFE = DsConstants.CNTR_FULL_EMPTY_CLS_CD_EMPTY;
                    } else {
                        if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "fullEmptyClsCd"))) {
                            ds_odrWrkPathStepDetail.setCellData(i, "fullEmptyClsCd", v_cntrFE);
                        }
                    }
                } else {
                    // 현단계가 운송인 경우
                    if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "fullEmptyClsCd"))) {
                        ds_odrWrkPathStepDetail.setCellData(i, "fullEmptyClsCd", v_cntrFE);
                    }
                }
            } else {
                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "fullEmptyClsCd"))) {
                    ds_odrWrkPathStepDetail.setCellData(i, "fullEmptyClsCd", v_fullEmptyClsCd);
                }
            }

        }

        // 작업점소, 매출귀속부서 설정
        scwin.f_setOdrWorkStepWorkLobranInternalSellLodept(i);
    }

    // 작업 단계를 역순으로 진행하며 동일 작업장 구분코드인 경우 출발작업장 코드를 설정한다.
    for (let j = ds_odrWrkPathStepDetail.getRowCount() - 1; j >= 0; j--) {
        if (j >= 0 && j < ds_odrWrkPathStepDetail.getRowCount() - 1) {
            if (ds_odrWrkPathStepDetail.getRowStatus(j) != "D") {	// RowStatus 가 Delete 가 아닌 경우
                // 다음 단계와 작업장 구분코드가 동일한 경우
                if (ds_odrWrkPathStepDetail.getCellData(j, "wrkPlClsCd").trim() == ds_odrWrkPathStepDetail.getCellData(j + 1, "wrkPlClsCd").trim()) {
                    // 작업장구분이 동일한 경우 다음 단계의 작업장/작업점소 정보를 설정한다.
                    if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "dptWrkPlCd"))) {
                        ds_odrWrkPathStepDetail.setCellData(j, "dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(j + 1, "dptWrkPlCd"));	// 출발작업장코드
                        ds_odrWrkPathStepDetail.setCellData(j, "dptWrkPlNm", ds_odrWrkPathStepDetail.getCellData(j + 1, "dptWrkPlNm"));	// 출발작업장명
                    }
                }

                // 현 단계가 운송단계인 경우 다음 단계의 출발지 정보를 도착지로 설정한다.
                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "wrkPlClsCd").trim()) && j < ds_odrWrkPathStepDetail.getRowCount() - 1) {
                    ds_odrWrkPathStepDetail.setCellData(j, "dptWrkPlNm", "");
                    ds_odrWrkPathStepDetail.setCellData(j, "arvWrkPlCd", ds_odrWrkPathStepDetail.getCellData(j + 1, "dptWrkPlCd"));
                }

                // 현단계가 운송(셔틀)이고 출발지(R)->도착지(CY), 출발지(CY)->도착지(R) 인경우
                // 철도역의 상위 작업장과 출도착지가 동일한 경우 작업단계 완료여부를 1로 설정한다. 아닌경우는 0으로 설정한다.
                if (ds_odrWrkPathStepDetail.getCellData(j, "wrkStpCd").trim() == DsConstants.WRK_STP_CD_SHUTTLE) {
                    let upperWrkPlCd = "";
                    if (ds_odrWrkPathStepDetail.getCellData(j - 1, "wrkPlClsCd").trim() == SdConstants.WRK_PL_CLS_CD_RAILSTN) {
                        // 이전 작업단계가 철도역인 경우
                        // 출발지(철도역)의 상위 작업장 정보 조회
                        if (!$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "dptWrkPlCd"))) {
                            upperWrkPlCd = await scwin.f_getUpperWorkPlCd(ds_odrWrkPathStepDetail.getCellData(j, "dptWrkPlCd"));
                        }
                        // 상위 작업장 정보가 존재하는 경우
                        if (!$c.gus.cfIsNull(upperWrkPlCd)) {
                            // 상위 작업장과 도착작업장이 동일한 경우
                            if (upperWrkPlCd == ds_odrWrkPathStepDetail.getCellData(j, "arvWrkPlCd")) {
                                ds_odrWrkPathStepDetail.setCellData(j, "completeYn", DsConstants.YN_YES);
                            } else {
                                ds_odrWrkPathStepDetail.setCellData(j, "completeYn", DsConstants.YN_NO);
                            }
                        } else {
                            ds_odrWrkPathStepDetail.setCellData(j, "completeYn", DsConstants.YN_NO);
                        }
                    } else if (ds_odrWrkPathStepDetail.getCellData(j + 1, "wrkPlClsCd").trim() == SdConstants.WRK_PL_CLS_CD_RAILSTN) {
                        // 다음 작업단계가 철도역인 경우
                        // 도착지(철도역)의 상위 작업장 정보 조회
                        if (!$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "arvWrkPlCd"))) {
                            upperWrkPlCd = await scwin.f_getUpperWorkPlCd(ds_odrWrkPathStepDetail.getCellData(j, "arvWrkPlCd"));
                        }
                        // 상위 작업장 정보가 존재하는 경우
                        if (!$c.gus.cfIsNull(upperWrkPlCd)) {
                            // 상위 작업장과 출발작업장이 동일한 경우
                            if (upperWrkPlCd == ds_odrWrkPathStepDetail.getCellData(j, "dptWrkPlCd")) {
                                ds_odrWrkPathStepDetail.setCellData(j, "completeYn", DsConstants.YN_YES);
                            } else {
                                ds_odrWrkPathStepDetail.setCellData(j, "completeYn", DsConstants.YN_NO);
                            }
                        } else {
                            ds_odrWrkPathStepDetail.setCellData(j, "completeYn", DsConstants.YN_NO);
                        }
                    }
                }
            }
        }

        // 작업점소, 매출귀속부서 설정
        scwin.f_setOdrWorkStepWorkLobranInternalSellLodept(j);
    }

    // 컨테이너 수입본선 오더중 작업경로가 자CY(F)로 선택된 경우 마지막 단계의 도착작업장을
    // 등록점소에 따라 부산지점(양산CY), 인천지점(인천CY)로 설정한다.
    // 기타 다른 지점은 모두 양산 CY로 설정한다.
    if (hid_odrKndCd.getValue() == DsConstants.ODR_KND_CD_IMP_CVSSL_CNTR_ODR) {
        // 선택된 작업경로가 자CY 인지 확인
        if (wrkPathInfo.ctrtWrkPathSeq != 0) {
            let find = ds_ctrtWrkPath.getAllJSON().find((item) => {
                if (item.ctrtWrkPathSeq == wrkPathInfo.ctrtWrkPathSeq && item.stdWrkPathNo == SdConstants.IMP_CVSSL_MCOM_CY_PATH) {
                    return true;
                }
                return false;
            });
            if (find) {
                // 선택된 작업경로가 자CY인 경우
                let lastRow = ds_odrWrkPathStepDetail.getRowCount() - 1;
                let r_arvWrkPlCd = ds_odrWrkPathStepDetail.getCellData(lastRow, "dptWrkPlCd");
                // 마지막 작업단계의 출발 작업장 지역이 부산(6)인 경우 양산 CY로 인천(4)인 경우 인천 CY, 기타인 경우 양산CY로 설정

                if (r_arvWrkPlCd.charAt(0) == "6") {
                    // 부산지역인 경우
                    r_arvWrkPlCd = SdConstants.PUSAN_DEFAULT_RETRV_CY;	// 양산 CY
                } else if (r_arvWrkPlCd.charAt(0) == "4") {
                    // 인천지역인 경우
                    r_arvWrkPlCd = SdConstants.INCHEON_DEFAULT_RETRV_CY;	// 인천 CY
                } else {
                    // 기타지역인 경우
                    r_arvWrkPlCd = SdConstants.PUSAN_DEFAULT_RETRV_CY;	// 양산 CY
                }

                ds_odrWrkPathStepDetail.setCellData(lastRow, "dptWrkPlCd", r_arvWrkPlCd);	// 작업장코드 <- 도착작업장코드

                let pCode = ds_odrWrkPathStepDetail.getCellData(lastRow, "dptWrkPlCd");

                // 작업장 설정
                await scwin.f_setWorkLobranNoDataAutoClose(lastRow, pCode, '', 'T', 'F', 'T', 'F', 'T');

                // 작업장구분코드가 운송인 경우 작업장명을 보여주지 않는다.
                const j = ds_odrWrkPathStepDetail.getRowCount();//TODO 임시로 j값 설정
                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "wrkPlClsCd").trim())) {//TODO asis는 갑자기 J등장, 실행되는가?
                    ds_odrWrkPathStepDetail.setCellData(j, "dptWrkPlNm", "");
                }

                // 작업장의 작업 점소/ 매출귀속부서 설정
                scwin.f_setOdrWorkStepWorkLobranInternalSellLodept(lastRow);
            }
        }
    }
};

/**
 * method
 * @name f_setWorkStepInfoRefreshForExport
 * @description f_setWorkStepInfoRefresh 함수 수출부분
 */
scwin.f_setWorkStepInfoRefreshForExport = async function () {
    let wrkPathInfo = ds_odrCntrWrkPath.getRowJSON(gr_odrCntrWrkPath.getFocusedRowIndex());
    let v_cntrFE = DsConstants.CNTR_FULL_EMPTY_CLS_CD_FULL;	// 컨테이너 F/E 기준값 (E)
    // 작업단계의 출발지 / 도착지 정보를 다시 설정한다. (역순)
    for (let i = ds_odrWrkPathStepDetail.getRowCount() - 1; i >= 0; i--) {
        const wrkPlClsCd = ds_odrWrkPathStepDetail.getCellData(i, "wrkPlClsCd").trim();
        // 해당 오더의 자가구분이 자가반출인 경우 운송 작업단계를 무매출로 설정한다.
        if (ds_order.getCellData(0, "selfClsCd") == DsConstants.SELF_CLS_CD_SELF_CRRYOUT
            && $c.gus.cfIsNull(wrkPlClsCd)) {
            ds_odrWrkPathStepDetail.setCellData(i, "selpchItemCd", SdConstants.SELPCH_ITEM_CD_NOSELL);	// 매출항목을 무매출로 설정한다.
            ds_odrWrkPathStepDetail.setCellData(i, "selpchItemNm", "무매출");	// 매출항목을 무매출로 설정한다.
        }

        if (ds_odrWrkPathStepDetail.getRowStatus(i) != "D") {	// RowStatus 가 Delete 가 아닌 경우
            if (i == ds_odrWrkPathStepDetail.getRowCount() - 1) {
                // 마지막 작업단계가 운송 단계인 경우 현 단계의 출발지를 도착지로 설정한다.
                if ($c.gus.cfIsNull(wrkPlClsCd)) {
                    ds_odrWrkPathStepDetail.setCellData(i, "arvWrkPlCd", ds_odrWrkPathStepDetail.getCellData(i, "dptWrkPlCd"));
                }
            } else {
                // 현단계 출발지, 도착지 정보 설정

                // 현 단계의 정보를 설정
                if ($c.gus.cfIsNull(wrkPlClsCd)) {
                    // 현 단계가 운송단계인 경우(다음 단계 출발지-> 현단계 도착지)
                    if (!$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i + 1, "dptWrkPlCd"))) {
                        ds_odrWrkPathStepDetail.setCellData(i, "arvWrkPlCd", ds_odrWrkPathStepDetail.getCellData(i + 1, "dptWrkPlCd"));
                    }
                } else {
                    //  현 단계가 운송단계가 아닌경우 - 직반출이 아닌경우(다음 단계 출발지-> 현단계 출발지)
                    if (wrkPathInfo.dptWrkPlClsCd != SdConstants.WRK_PL_CLS_CD_PIER || wrkPathInfo.dptWrkPlCd != wrkPathInfo.arvWrkPlCd) {
                        if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "dptWrkPlCd")) && !$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i + 1, "dptWrkPlCd")))
                            ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(i + 1, "dptWrkPlCd"));
                    }
                }

                // 다음 단계와 작업장 구분코드가 동일한 경우
                if (wrkPlClsCd == ds_odrWrkPathStepDetail.getCellData(i + 1, "wrkPlClsCd").trim()) {
                    // 작업장구분이 동일한 경우 이전 단계의 작업장/작업점소 정보를 설정한다.
                    if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "dptWrkPlCd"))) {
                        ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(i + 1, "dptWrkPlCd"));	// 출발작업장코드
                        ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlNm", ds_odrWrkPathStepDetail.getCellData(i + 1, "dptWrkPlNm"));	// 출발작업장명
                    }
                }
            }

            // 첫번째 단계의 출발지 설정
            if (i == 0) {
                // 첫번째 작업단계가 운송단계인 경우 현 단계의 도착지를 출발지로 설정한다.
                if ($c.gus.cfIsNull(wrkPlClsCd && !$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "arcWrkPlCd")))) {
                    ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(i, "arvWrkPlCd"));
                }
            }

            // 현단계의 정보를 확인하여 FULL_EMPTY_CLS_CD 설정한다.
            // 수출일반 인경우 도착작업장 이전단계 까지는 E, 도착작업장 이후 단계는 F 로 설정한다.
            // 수출일반 오더가 아닌경우는 해당 컨테이너의 F/E 정보를 설정한다.
            if (hid_odrKndCd.getValue() == DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR) {
                // 현단계가 운송단계인지 확인
                // 운송 단계인 경우 단계의 도착지와 컨테이너의 도착지가 동일한 경우 까지 "E" 설정 , 이후 단계는 "F" 설정
                if (!$c.gus.cfIsNull(wrkPlClsCd)) {
                    // 현단계가 운송이 아닌 경우
                    if (ds_odrWrkPathStepDetail.getCellData(i, "dptWrkPlCd") == wrkPathInfo.dptWrkPlCd) {// 출발 작업장코드
                        if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "fullEmptyClsCd"))) {
                            ds_odrWrkPathStepDetail.setCellData(i, "fullEmptyClsCd", v_cntrFE);
                        }
                        v_cntrFE = DsConstants.CNTR_FULL_EMPTY_CLS_CD_EMPTY;
                    } else {
                        if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "fullEmptyClsCd"))) {
                            ds_odrWrkPathStepDetail.setCellData(i, "fullEmptyClsCd", v_cntrFE);
                        }
                    }
                } else {
                    // 현단계가 운송인 경우
                    if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "fullEmptyClsCd"))) {
                        ds_odrWrkPathStepDetail.setCellData(i, "fullEmptyClsCd", v_cntrFE);
                    }
                }
            } else {
                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "fullEmptyClsCd"))) {
                    ds_odrWrkPathStepDetail.setCellData(i, "fullEmptyClsCd", wrkPathInfo.fullEmptyClsCd);   // FULLEMPTY구분코드
                }
            }
        }

        // 작업점소, 매출귀속부서 설정
        scwin.f_setOdrWorkStepWorkLobranInternalSellLodept(i);
    }

    // 작업 단계를 진행하며 동일 작업장 구분코드인 경우 출발작업장 코드를 설정한다.
    for (let j = 0; j < ds_odrWrkPathStepDetail.getRowCount(); j++) {
        if (ds_odrWrkPathStepDetail.getRowStatus(j) != "D") {	// RowStatus 가 Delete 가 아닌 경우
            if (j > 0) {
                // 이전 단계와 작업장 구분코드가 동일한 경우
                if (ds_odrWrkPathStepDetail.getCellData(j, "wrkPlClsCd").trim() == ds_odrWrkPathStepDetail.getCellData(j - 1, "wrkPlClsCd").trim()) {
                    // 작업장구분이 동일한 경우 이전 단계의 작업장/작업점소 정보를 설정한다.
                    if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "dptWrkPlCd")) && !$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j - 1, "dptWrkPlCd"))) {
                        ds_odrWrkPathStepDetail.setCellData(j, "dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(j - 1, "dptWrkPlCd"));	// 출발작업장코드
                        ds_odrWrkPathStepDetail.setCellData(j, "dptWrkPlNm", ds_odrWrkPathStepDetail.getCellData(j - 1, "dptWrkPlNm"));	// 출발작업장명
                    }
                }

                // 현 단계가 운송단계인 경우 이전 단계의 출발지 정보를 출발지로 설정한다.
                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "wrkPlClsCd").trim()) && j < ds_odrWrkPathStepDetail.getRowCount() - 1) {
                    ds_odrWrkPathStepDetail.setCellData(j, "dptWrkPlNm", "");
                    ds_odrWrkPathStepDetail.setCellData(j, "dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(j - 1, "dptWrkPlCd"));
                }
            }

            // 작업점소, 매출귀속부서 설정
            scwin.f_setOdrWorkStepWorkLobranInternalSellLodept(j);
        }
    }
};

/**
 * method
 * @name f_setWorkPathStepDetail
 * @description 작업단계 정보를 설정한다.
 * - 작업경로별 조회된 오더작업단계, 계약작업단계 정보 중
 *   오더작업단계 정보가 존재하는 경우 작업단계 그리드에 오더작업단계정보를 설정하고
 *   오더작업단계 정보가 존재하지 않는경우 계약작업단계정보를 작업단계 그리드에 설정한다.
 */
scwin.f_setWorkPathStepDetail = async function () {
    scwin.wrkLobranCd = scwin.lobranCd;	// 작업점소코드
    scwin.wrkLobranNm = scwin.lobranNm;	// 작업점소명
    scwin.setInternalSellLodeptInfo(ds_lobran.getCellData(0, "lobranCd"), ds_lobran.getCellData(0, "lobranNm"));
    scwin.wrkLobranCdRow = 0;	// 작업점소 설정 ROW 초기화

    ds_odrWrkPathStepDetail.setBroadcast(false, false);
    let row = gr_odrCntrWrkPath.getFocusedRowIndex();
    if (ds_odrWrkPathStep.getRowCount() && ds_odrCntrWrkPath.getCellData(row, "ctrtWrkPathSeq") == ds_odrCntrWrkPath.getOriginalCellData(row, "ctrtWrkPathSeq")) {
        scwin.f_setOdrWrkPathStepToWrkPathStepDetail();
        $c.gus.cfEnableObjects([btnOrderWrkStepDetail, btnDcSc]);
    } else if (ds_ctrtWrkPathStep.getRowCount()) {
        await scwin.f_setCtrtWrkPathStepToWrkPathStepDetail();
    } else {
        // 작업단계정보 (오더작업단계/계약작업단계)가 존재하지 않습니다.
        await $c.gus.cfAlertMsg(MSG_CM_ERR_003);
        ds_odrWrkPathStepDetail.setBroadcast(true, true);
        return;
    }

    scwin.setOdrWrkPathStepDetailColumnFilter(true);
    ds_odrWrkPathStepDetail.setBroadcast(true, true);
    ds_odrWrkPathStepDetail.modifyAllStatus("R");

    // 버튼 활성화
    $c.gus.cfEnableBtnOnly([btnInsertRow, btnDeleteRow, btnUndoMark]);
};

/**
 * method
 * @name f_setOdrWrkPathStepToWrkPathStepDetail
 * @description 오더작업단계정보를 작업단계 그리드에 설정한다.
 */
scwin.f_setOdrWrkPathStepToWrkPathStepDetail = function () {
    let allData = ds_odrWrkPathStep.getAllJSON();
    ds_odrWrkPathStepDetail.setJSON(allData, true);
    for (let i = 0; i < ds_odrWrkPathStepDetail.getRowCount(); i++) {
        const wrkPlClsCd = ds_odrWrkPathStepDetail.getCellData(i, "wrkPlClsCd").trim();
        if ($c.gus.cfIsNull(wrkPlClsCd)) {	// 작업구분이 운송인 경우 작업장 표시 안함.
            ds_odrWrkPathStepDetail.setOriginalCellData(i, "dptWrkPlNm", "");
            ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlNm", "");
        }

        if (ds_odrWrkPathStepDetail.getCellData(i, "selpchItemCd") == SdConstants.SELPCH_ITEM_CD_NOSELL && !$c.gus.cfIsNull(wrkPlClsCd)) {
            ds_odrWrkPathStepDetail.setCellData(i, "wrkLobranCd", "");
            ds_odrWrkPathStepDetail.setCellData(i, "wrkLobranNm", "");

            ds_odrWrkPathStepDetail.setCellData(i, "internalSellLodeptCd", "");
            ds_odrWrkPathStepDetail.setCellData(i, "internalSellLodeptNm", "");
        }
    }

    ds_odrWrkPathStepDetail.modifyAllStatus("R");

    // 자동 설정된 작업단계 정보를 임시 데이터셋에 복사한다.
    scwin.f_copyTempDataSet();
};

/**
 * method
 * @name sortOdrWrkPathStepDetail
 * @description ds_odrWrkPathStepDetail 데이터 정렬용
 */
scwin.sortOdrWrkPathStepDetail = function (item1, item2) {
    if (item1.odrNo !== item2.odrNo) {
        if (item1.odrNo > item2.odrNo) {
            return 1;
        }
        return -1;
    }
    if (item1.cntrSeq !== item2.cntrSeq) {
        return ($c.num.parseInt(item1.cntrSeq) - $c.num.parseInt(item2.cntrSeq));
    }
    if (item1.odrWrkPathSeq !== item2.odrWrkPathSeq) {
        return ($c.num.parseInt(item1.odrWrkPathSeq) - $c.num.parseInt(item2.odrWrkPathSeq));
    }
    if (item1.odrWrkStpSeq !== item2.odrWrkStpSeq) {
        return ($c.num.parseInt(item1.odrWrkStpSeq) - $c.num.parseInt(item2.odrWrkStpSeq));
    }
    return 0;
};

/**
 * method
 * @name f_setCtrtWrkPathStepToWrkPathStepDetail
 * @description 계약작업단계정보를 작업단계 그리드에 설정한다.
 */
scwin.f_setCtrtWrkPathStepToWrkPathStepDetail = async function () {
    let row = gr_odrCntrWrkPath.getFocusedRowIndex();
    let odrCntrWrkPath = ds_odrCntrWrkPath.getRowJSON(row);
    const selfClsCd = ds_order.getCellData(0, "selfClsCd");
    let addData = ds_ctrtWrkPathStep.getAllJSON().map((item) => {
        let selpchItemCd = SdConstants.SELPCH_ITEM_CD_NOSELL;	// 매출항목을 무매출로 설정한다.
        let selpchItemNm = "무매출";	// 매출항목을 무매출로 설정한다.
        if (selfClsCd == DsConstants.SELF_CLS_CD_SELF_CRRYOUT && $c.gus.cfIsNull(item.wrkPlClsCd.trim())) {
            selpchItemCd = item.selpchItemCd;
            selpchItemNm = item.selpchItemNm;
        }
        return {
            "odrNo": odrCntrWrkPath.odrNo,	// 오더번호
            "cntrSeq": odrCntrWrkPath.cntrSeq,	// 컨테이너순번
            "odrWrkPathSeq": odrCntrWrkPath.odrWrkPathSeq,	// 오더작업경로순번
            "ctrtWrkPathSeq": odrCntrWrkPath.ctrtWrkPathSeq,	// 계약작업경로순번
            "odrWrkPathNm": item.ctrtWrkPathNm,		// 작업경로명
            "odrWrkStpSeq": item.ctrtWrkStpSeq,	// 오더작업단계순번
            "wrkPlClsCd": item.wrkPlClsCd,	// 작업장구분코드
            "wrkStpCd": item.wrkStpCd,	// 작업단계코드
            "wrkStpNm": item.wrkStpNm,	// 작업단계명
            "bizDomCd": item.bizDomCd,	// 사업영역코드
            "selpchItemCd": selpchItemCd,   // 매출입항목코드
            "selpchItemNm": selpchItemNm,   // 매출입항목명
        }
    });
    ds_odrWrkPathStepDetail.setJSON(addData, true);

    ds_odrWrkPathStepDetail.modifyAllStatus("R");
    scwin.v_dptWrkPlCd = "";
    scwin.v_bizDomCd = "";

    // 출발지 도착지 정보를 설정한다.
    await scwin.f_setOdrWrkPathStepDptArv();

    // 작업 단계 정보 재설정
    await scwin.f_setWorkStepInfoRefresh();
};

/**
 * method
 * @name f_setOdrWrkPathStepDptArv
 * @description 작업단계 출도착지 정보를 설정한다.
 * - 처리 규칙
 * 	1. 선택된 작업 경로의 계약작업단계를 순차적으로 검색하여 출발작업장구분과 동일한 작업장구분의 첫번째 작업장에 출발 작업장 정보를 설정
 *  2. 선택된 작업 경로의 계약작업단계를 역순으로 검색하여 도착작업장구분과 동일한 작업장구분의 첫번째 작업장에 도착 작업장 정보를 설정
 *  3. 출발작업장과 도착 작업장이 동일한 경우 도착작업장을 설정하지 않는다.
 *  4. 출발작업장과 도착작업장 정보가 없는 경우 설정하지 않는다.
 *  5. 작업장구분코드가 D, G 인 경우는 동일한 경우로 인식한다.
 */
scwin.f_setOdrWrkPathStepDptArv = async function () {
    let v_dptRow = 0;
    let v_impExpDomesticClsCd = ds_order.getCellData(0, "impExpDomesticClsCd");	// 수출입내수구분코드 - IMP_EXP_DOMESTIC_CLS_CD
    let row = gr_odrCntrWrkPath.getFocusedRowIndex();
    let odrCntrWrkPath = ds_odrCntrWrkPath.getRowJSON(row);

    let v_dptWrkPlCd = odrCntrWrkPath.dptWrkPlCd;	// 출발 작업장코드
    let v_dptWrkPlNm = odrCntrWrkPath.dptWrkPlNm;	// 출발 작업장명
    let v_dptWrkPlClsCd = odrCntrWrkPath.dptWrkPlClsCd;	// 출발 작업장 구분코드

    let v_arvWrkPlCd = odrCntrWrkPath.arvWrkPlCd;	// 도착 작업장코드
    let v_arvWrkPlNm = odrCntrWrkPath.arvWrkPlNm;	// 도착 작업장명
    let v_arvWrkPlClsCd = odrCntrWrkPath.arvWrkPlClsCd;	// 도착 작업장 구분코드

    let r_arvWrkPlCd = "";

    if (v_impExpDomesticClsCd == DsConstants.IMP_CD) {
        // 수입인 경우
        await scwin.f_setOdrWrkPathStepDptArvForImport(); //f_setOdrWrkPathStepDptArv함수가 너무 길어서 별도 함수로 빼버림
    } else if (v_impExpDomesticClsCd == DsConstants.EXP_CD) {
        // 수출인 경우
        await scwin.f_setOdrWrkPathStepDptArvForExport(); //f_setOdrWrkPathStepDptArv함수가 너무 길어서 별도 함수로 빼버림
    } else {
        // 수입, 수출이 아닌 경우
        // 작업단계 정보를 완성한다. - 출발지 정보 설정
        for (let i = 0; i < ds_odrWrkPathStepDetail.getRowCount(); i++) {
            // 출발 작업장 설정
            if (!$c.gus.cfIsNull(v_dptWrkPlCd)) {
                const wrkPlClsCd = ds_odrWrkPathStepDetail.getCellData(i, "wrkPlClsCd").trim();
                if (v_dptWrkPlClsCd == SdConstants.WRK_PL_CLS_CD_DOOR || v_dptWrkPlClsCd == SdConstants.WRK_PL_CLS_CD_RGN) {
                    // 작업장 구분이 Door(D) 나 지역(G) 인경우
                    if (ds_odrWrkPathStepDetail.getCellData(i, "wrkPlClsCd") == SdConstants.WRK_PL_CLS_CD_RGN || ds_odrWrkPathStepDetail.getCellData(i, "wrkPlClsCd") == SdConstants.WRK_PL_CLS_CD_DOOR) {
                        // 출발작업장 구분코드와 작업단계구분코드가 같은 경우 해당 단계의 작업장정보에 출발 작업장 정보를 설정
                        ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlCd", v_dptWrkPlCd);	// 작업장코드 <- 출발작업장코드
                        ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlNm", v_dptWrkPlNm);	// 작업장명 < - 출발작업장명

                        let pCode = ds_odrWrkPathStepDetail.getCellData(i, "dptWrkPlCd");
                        // 작업장 설정
                        await scwin.f_setWorkLobranNoDataAutoClose(i, pCode, '', 'T', 'F', 'T', 'F', 'T');
                        // 작업장구분코드가 운송인 경우 작업장명을 보여주지 않는다.
                        if ($c.gus.cfIsNull(wrkPlClsCd)) {
                            ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlNm", "");
                        }

                        v_dptRow = i;
                        break;
                    }
                } else if ((v_dptWrkPlClsCd == SdConstants.WRK_PL_CLS_CD_PIER || v_arvWrkPlClsCd == SdConstants.WRK_PL_CLS_CD_BERTH) && v_dptWrkPlClsCd == v_arvWrkPlClsCd) {
                    // 출발작업장 구분이 부두(P), 선석(B) 이고 출발작업장구분코드와 도착작업장 구분코드가 동일한
                    if (hid_odrKndCd.getValue() == DsConstants.ODR_KND_CD_EXP_CVSSL_CNTR_ODR) {
                        // 수출본선오더인 경우 - 도착작업장 구분이 부두(P), 선석(B) 인 경우

                        if (v_dptWrkPlCd == v_arvWrkPlCd) {
                            // 출발작업장과 도착작업장이 동일한 경우
