/**
 * method
 * @name f_setOdrWrkPathStepDptArvForImport
 * @description f_setOdrWrkPathStepDptArv 함수 수입부분
 */
scwin.f_setOdrWrkPathStepDptArvForImport = async function () {
    let v_dptRow = 0;
    let v_impExpDomesticClsCd = ds_order.getCellData(0, "impExpDomesticClsCd");	// 수출입내수구분코드 - IMP_EXP_DOMESTIC_CLS_CD
    let row = gr_odrCntrWrkPath.getFocusedRowIndex();
    let odrCntrWrkPath = ds_odrCntrWrkPath.getRowJSON(row);

    let v_dptWrkPlCd = odrCntrWrkPath.dptWrkPlCd;	// 출발 작업장코드
    let v_dptWrkPlNm = odrCntrWrkPath.dptWrkPlNm;	// 출발 작업장명
    let v_dptWrkPlClsCd = odrCntrWrkPath.dptWrkPlClsCd;	// 출발 작업장 구분코드

    let v_arvWrkPlCd = odrCntrWrkPath.arvWrkPlCd;	// 도착 작업장코드
    let v_arvWrkPlNm = odrCntrWrkPath.arvWrkPlNm;	// 도착 작업장명
    let v_arvWrkPlClsCd = odrCntrWrkPath.arvWrkPlClsCd;	// 도착 작업장 구분코드

    let r_arvWrkPlCd = "";

    // 작업단계 정보를 완성한다. - 도착지 정보 설정
    for (let j = ds_odrWrkPathStepDetail.getRowCount() - 1; j >= 0; j--) {
        // 도착 작업장은 출발 작업장 이전 단계에 설정할수 없습니다.
        if (v_dptRow > 0 && v_dptRow >= j) {
            await $c.gus.cfAlertMsg("도착 작업장은 출발 작업장 이전 단계에 설정할수 없습니다.");	// 도착 작업장은 출발 작업장 이전 단계에 설정할수 없습니다.
            break;
        }

        // 도착 작업장 설정
        if (!$c.gus.cfIsNull(v_arvWrkPlCd)) {
            if (v_arvWrkPlClsCd == SdConstants.WRK_PL_CLS_CD_DOOR || v_arvWrkPlClsCd == SdConstants.WRK_PL_CLS_CD_RGN) {
                // 작업장 구분이 Door(D), 지역(G) 인경우
                if (ds_odrWrkPathStepDetail.getCellData(j, "wrkPlClsCd") == SdConstants.WRK_PL_CLS_CD_RGN || ds_odrWrkPathStepDetail.getCellData(j, "wrkPlClsCd") == SdConstants.WRK_PL_CLS_CD_DOOR) {
                    if (v_impExpDomesticClsCd == DsConstants.IMP_EXP_CLS_CD_IMP) {
                        // 수입인 경우 이미 설정된 정보를 도착지 정보로 대체한다.
                        // 도착작업장 구분코드와 작업단계구분코드가 같은 경우 해당 단계의 작업장정보에 도착 작업장 정보를 설정
