/**
 * method
 * @name f_copyTempDataSet
 * @description 작업경로별 작업단계 정보를 저장하여 동일 작업경로 선택시 참조한다.
 */
scwin.f_copyTempDataSet = function () {
    scwin.setOdrWrkPathStepDetailTempColumnFilter();

    let row = gr_odrCntrWrkPath.getFocusedRowIndex();
    // 선택된 컨테이너 작업경로 정보를 저장
    scwin.f_CopyDataSetOdrCntrWrkPath(row, ds_odrCntrWrkPath, ds_odrCntrWrkPathTemp);

    if (ds_odrWrkPathStepDetailTemp.getRowCount()) {
        // 선택된 계약작업경로의 작업단계 정보가 존재하는 경우
        // 저장되어 있던 작업단계 정보를 삭제
        scwin.deleteAll(ds_odrWrkPathStepDetailTemp);//TODO asis는 deleteAll 사용함, tobe에서 removeAll 사용해야 되는지 확인 필요
    }
    // 작업단계 정보를 복사
    scwin.f_CopyDataSetValue(ds_odrWrkPathStepDetail, ds_odrWrkPathStepDetailTemp);
    ds_odrWrkPathStepDetailTemp.multisort({ sortIndex: "odrNo cntrSeq odrWrkPathSeq odrWrkStpSeq", sortOrder: "1 1 1 1", });
    ds_odrWrkPathStepDetailTemp.modifyAllStatus("R");
};

/**
 * method
 * @name f_CopyDataSetValue
 * @description 임시 저장된 작업단계 정보를 해당 작업경로의 작업단계 정보로 복사한다.
 * sourceDs의 내용을 destDs로 복사한다.
 */
scwin.f_CopyDataSetValue = function (sourceDs, destDs) {
    let row = gr_odrCntrWrkPath.getFocusedRowIndex();
    let odrCntrWrkPath = ds_odrCntrWrkPath.getRowJSON(row);

    let allData = sourceDs.getAllFilteredJSON().filter((item) => item.rowStatus != "D"); // RowStatus 가 Delete 가 아닌 경우
    for (let item of allData) {
        item.cntrSeq = odrCntrWrkPath.cntrSeq;
        item.odrWrkPathSeq = odrCntrWrkPath.odrWrkPathSeq;
        item.ctrtWrkPathSeq = odrCntrWrkPath.ctrtWrkPathSeq;
        item.fullEmptyClsCd = "";
        if (hid_odrKndCd.getValue() != DsConstants.ODR_KND_CD_IMP_GNRL_CNTR_ODR && hid_odrKndCd.getValue() != DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR) {
            // 수입일반 , 수출일반 오더가 아닌 경우 컨테이너별 F/E 정보를 설정한다.
            item.fullEmptyClsCd = odrCntrWrkPath.fullEmptyClsCd;
        }
    }
    destDs.setJSON(allData, true);
};

/**
 * method
 * @name f_CopyDataSetOdrCntrWrkPath
 * @description 선택된 컨테이너 작업경로 정보를 임시 데이터셋에 복사한다.
 */
scwin.f_CopyDataSetOdrCntrWrkPath = function (row, sourceDs, destDs) {
    if (row < 0 || sourceDs.getRowStatus(row) != "D") {
        return;
    };
    // RowStatus 가 Delete 가 아닌 경우
    let allData = sourceDs.getAllJSON();
    destDs.setJSON(allData, false);
};

