/**
 * method
 * @name f_checkWorkStepEditMode
 * @description 오더 작업단계 수정 모드 확인
 */
scwin.f_checkWorkStepEditMode = function (row) {
    if (gr_odrWrkPathStepDetail.getReadOnly("grid")) {
        $c.gus.cfDisableBtnOnly([btnInsertRow, btnDeleteRow, btnUndoMark]);
        return;	// 실적 발생시 수정모드 사용금지
    }

    if (row < 0 && ds_odrWrkPathStepDetail.getRowCount()) {
        row = 0;
    }

    if (row < 0) {
        return;
    }

    let rowObj = ds_odrWrkPathStepDetail.getRowJSON(row);
    let v_odrWrkStpSeq = $c.num.parseInt(rowObj.odrWrkStpSeq);

    if (row == 0 || v_odrWrkStpSeq == 10) {
        // 첫번째 row 와 계약작업순번이 10인 경우는 수정 할수 없음
        $c.gus.cfEnableBtnOnly([btnInsertRow]);
        $c.gus.cfDisableBtnOnly([btnDeleteRow, btnUndoMark]);
        return;
    }

    if (row == ds_odrWrkPathStepDetail.getRowCount() - 1) {
        // 마직막 row는 수정할수 없음.
        $c.gus.cfDisableBtnOnly([btnInsertRow, btnDeleteRow, btnUndoMark]);
        return;
    }

    if (v_odrWrkStpSeq % 10 != 0) {
        // 추가된 오더 작업단계
        $c.gus.cfEnableBtnOnly([btnInsertRow, btnDeleteRow, btnUndoMark]);
        return;
    }

    // 계약작업단계(작업단계순번이 10단위인 경우)중 변경불가한 경우
    // 0. 운송단계는 삭제할수 없음. (셔틀, 육송은 삭제가능)
    // 1. DOOR 운송(DOO운송->DOOR->DOOR회수)
    // 2. 철송 (철도역->철송->철도역)
    // 3. 해송 (해송부두->해송->해송부두)

    // 작업단계순번을 10으로 나눈 나머지가 0인 경우 - 계약작업단계에서 가져온 작업단계

    let nextRowObj = ds_odrWrkPathStepDetail.getRowJSON(row + 1);
    const odrWrkStpSeqMod10 = $c.num.parseInt(nextRowObj.odrWrkStpSeq) % 10;
    // 운송단계인 경우
    if ($c.gus.cfIsNull(rowObj.wrkPlClsCd.trim())) {
        // 0. 운송단계는 삭제할수 없음. (셔틀, 육송은 삭제가능)
        if (rowObj.wrkStpCd == DsConstants.WRK_STP_CD_SHUTTLE || rowObj.wrkStpCd == DsConstants.WRK_STP_CD_GROUND_TRANS) {
            // 셔틀, 육송 단계인 경우 수정가능
            $c.gus.cfEnableBtnOnly([btnInsertRow, btnDeleteRow, btnUndoMark]);
        } else {
            $c.gus.cfDisableBtnOnly([btnDeleteRow, btnUndoMark]);
            if (nextRowObj.wrkPlClsCd == SdConstants.WRK_PL_CLS_CD_DOOR && odrWrkStpSeqMod10 == 0) {
                // 1. 운송다음 단계가 DOOR인경우 (DOO운송->DOOR) 변경불가
                $c.gus.cfDisableBtnOnly([btnInsertRow, btnUndoMark]);
            } else if (nextRowObj.wrkPlClsCd == SdConstants.WRK_PL_CLS_CD_RAILSTN && odrWrkStpSeqMod10 == 0) {
                // 2. 운송다음 단계가 철도역인 경우 (철송->철도역) 변경불가
                $c.gus.cfDisableBtnOnly([btnInsertRow, btnUndoMark]);
            } else if (nextRowObj.wrkPlClsCd == SdConstants.WRK_PL_CLS_CD_MARTRPIER && odrWrkStpSeqMod10 == 0) {
                // 3. 운송다음 단계가 해송부두인 경우 (해송->해송부두) 변경불가
                $c.gus.cfDisableBtnOnly([btnInsertRow, btnUndoMark]);
            } else {
                $c.gus.cfEnableBtnOnly([btnInsertRow]);
            }
        }
        return;
    }

    switch (rowObj.wrkPlClsCd) {
        case SdConstants.WRK_PL_CLS_CD_DOOR:        // DOOR 단계인 경우
            if ($c.gus.cfIsNull(nextRowObj.wrkPlClsCd.trim()) && odrWrkStpSeqMod10 == 0) {
                // DOOR 다음단계가 운송단계인 경우(DOO운송->DOOR) 변경불가
                $c.gus.cfDisableBtnOnly([btnInsertRow, btnDeleteRow, btnUndoMark]);
            } else {
                $c.gus.cfDisableBtnOnly([btnDeleteRow, btnUndoMark]);
                $c.gus.cfEnableBtnOnly([btnInsertRow]);
            }
            break;

        case SdConstants.WRK_PL_CLS_CD_RAILSTN:     // 철도역 단계인 경우
            if ($c.gus.cfIsNull(nextRowObj.wrkPlClsCd.trim()) && odrWrkStpSeqMod10 == 0) {
                // 철도역 다음단계가 운송단계인 경우(철도역->철송) 변경불가
                $c.gus.cfDisableBtnOnly([btnInsertRow, btnDeleteRow, btnUndoMark]);
            } else {
                $c.gus.cfDisableBtnOnly([btnDeleteRow, btnUndoMark]);
                $c.gus.cfEnableBtnOnly([btnInsertRow]);
            }
            break;

        case SdConstants.WRK_PL_CLS_CD_MARTRPIER:   // 해송부두 단계인 경우
            if ($c.gus.cfIsNull(nextRowObj.wrkPlClsCd.trim()) && odrWrkStpSeqMod10 == 0) {
                // 해송부두 다음단계가 운송단계인 경우(해송부두->해송) 변경불가
                $c.gus.cfDisableBtnOnly([btnInsertRow, btnDeleteRow, btnUndoMark]);
            } else {
                $c.gus.cfDisableBtnOnly([btnDeleteRow, btnUndoMark]);
                $c.gus.cfEnableBtnOnly([btnInsertRow]);
            }
            break;

        default:
            // 위 경우가 아닌경우 수정 가능
            $c.gus.cfEnableBtnOnly([btnInsertRow, btnDeleteRow, btnUndoMark]);
            break;
    }
};

