/**
 * method
 * @name f_chkOdrWorkStepCanRowPosChange
 * @description
 * 컨테이너 작업단계 설정 정확성 확인
 * 수입본선오더, 수출본선오더의 경우 확인
 *	1. 작업경로 확인 규칙
 *		1.1. 도착작업장 구분이 자CY 이며 컨테이너가 EMPTY 인 경우 : 자CY EMPTY (기준작업경로로 확인)
 *		1.2. 도착작업장 구분이 자CY 이며 컨테이너가 FULL 인 경우 : 자CY (기준작업경로로 확인)
 *		1.3. 도착작업장 구분이 타CY 인 경우 : 타CY EMPTY (기준작업경로로 확인)
 *		1.4. 출발작업장과 도착작업장이 동일한 경우 : 직반출/직반입 (기준작업경로로 확인)
 *		1.5. 도착작업장 구분이 부두인 경우(출발작업장과 도착작업이 다른경우) : 셔틀 (기준작업경로로 확인)
 *		1.6. 작업경로가 ON-DOCK 으로 설정된 경우 작업경로가 설정되지 않은 컨테이너의 작업경로를 ON-DOCK으로 설정한다.
 *		1.1. 출발작업장 구분이 자CY 이며 컨테이너가 EMPTY 인 경우 : 자CY EMPTY (기준작업경로로 확인)
 *		1.2. 출발작업장 구분이 자CY 이며 컨테이너가 FULL 인 경우 : 자CY (기준작업경로로 확인)
 *		1.3. 출발작업장 구분이 타CY 인 경우 : 타CY EMPTY (기준작업경로로 확인)
 *		1.4. 출발작업장과 도착작업장이 동일한 경우 : 직반출/직반입 (기준작업경로로 확인)
 *		1.5. 출발작업장 구분이 부두인 경우(출발작업장과 도착작업이 다른경우) : 셔틀 (기준작업경로로 확인)
 *		1.6. 작업경로가 ON-DOCK 으로 설정된 경우 작업경로가 설정되지 않은 컨테이너의 작업경로를 ON-DOCK으로 설정한다.
 *	2. 작업단계 확인 규칙
 *		2.1. 컨테이너의 F/E 와 단계의 F/E 정보가 일치하여야 함.
 *		2.2. 컨테이너의 출.도착지 정보와 작업단계의 출.도착지 정보 설정이 동일하여야 함.
 */
scwin.f_chkOdrWorkStepCanRowPosChange = function () {
    //scwin.ds_odrCntrWrkPath_onbeforerowpositionchange함수를 async로 선언하면 안되기 때문에 이함수도 async 함수가 아니게 한다.
    let row = gr_odrCntrWrkPath.getFocusedRowIndex();
    let rowObj = ds_odrCntrWrkPath.getRowJSON(row);
    let matched = ds_odrCntrWrkPath.getMatchedJSON("ctrtWrkPathSeq", rowObj.ctrtWrkPathSeq, true);
    if (rowObj.ctrtWrkPathSeq == 0) {
        return true;
    }

    // 수입본선오더, 수출본선오더의 경우 확인
    if (hid_odrKndCd.getValue() == DsConstants.ODR_KND_CD_IMP_CVSSL_CNTR_ODR) {
        // 수입본선오더의 경우 확인
        // 작업경로 확인

        // 선택된 작업경로가 ON-DOCK 인지 확인
        for (let item of matched) {
            if (item.stdWrkPathNo == SdConstants.IMP_CVSSL_ON_DOCK_PATH) {
                return true;
            }
        }

        if (rowObj.dptWrkPlCd == rowObj.arvWrkPlCd) {
            // 출발작업장과 도착작업장이 동일한 경우
            // 선택된 작업경로가 직반출인지 확인
            for (let item of matched) {
                if (item.stdWrkPathNo != SdConstants.IMP_CVSSL_DRT_WRK_CRRYOUT_PATH) {
                    $c.gus.cfAlertMsg(scwin.DMessage["I0108"]);	// 해당 컨테이너의 출발작업장과과 도착작업장이 동일하기 때문에 직반출 작업경로를 선택하여야 합니다.
                    return false;
                }
            }
        } else if (rowObj.dptWrkPlCd != rowObj.arvWrkPlCd && rowObj.arvWrkPlClsCd == SdConstants.WRK_PL_CLS_CD_PIER) {
            // 도착작업장 구분이 부두인 경우
            // 선택된 작업경로가 부두인지 확인
            for (let item of matched) {
                if (item.stdWrkPathNo != SdConstants.IMP_CVSSL_PIER) {
                    $c.gus.cfAlertMsg(scwin.DMessage["I0109"]);	// 해당 컨테이너의 도착작업장 구분이 부두인 경우 수입본선 부두 작업경로를 선택하여야 합니다.
                    return false;
                }
            }
        } else if (rowObj.arvWrkPlClsCd == SdConstants.WRK_PL_CLS_CD_CY) {
            // 도착작업장 구분이 자CY인 경우
            if (rowObj.fullEmptyClsCd == DsConstants.CNTR_FULL_EMPTY_CLS_CD_FULL) {
                // 해당 컨테이너가 FULL 인 경우
                // 선택된 작업경로가 자CY 인지 확인
                for (let item of matched) {
                    if (item.stdWrkPathNo == SdConstants.IMP_CVSSL_SHUTTLE_PATH) {
                        return true;	// 선택된 작업경로가 셔틀 경로인 경우 제외
                    } else if (item.stdWrkPathNo != SdConstants.IMP_CVSSL_MCOM_CY_PATH) {
                        $c.gus.cfAlertMsg(scwin.DMessage["I0111"]);	// 해당 컨테이너의 도착작업장 구분이 자CY이고 FULL인 경우 수입본선 자CY 작업경로를 선택하여야 합니다.
                        return false;
                    }
                }
            } else if (rowObj.fullEmptyClsCd == DsConstants.CNTR_FULL_EMPTY_CLS_CD_EMPTY) {
                // 해당 컨테이너가 EMPTY 인 경우
                // 선택된 작업경로가 자CY_E 인지 확인
                for (let item of matched) {
                    if (item.stdWrkPathNo == SdConstants.IMP_CVSSL_DRT_WRK_CRRYIN_PATH_H
                        || item.stdWrkPathNo == SdConstants.IMP_CVSSL_DRT_WRK_CRRYIN_PATH_S
                        || item.stdWrkPathNo == SdConstants.IMP_CVSSL_SHUTTLE_PATH) {
                        return true;	// 선택된 작업경로가 직반입, 셔틀 경로인 경우 제외
                    } else if (item.stdWrkPathNo != SdConstants.IMP_CVSSL_MCOM_CY_EMPTY_PATH) {
                        $c.gus.cfAlertMsg(scwin.DMessage["I0113"]);	// 해당 컨테이너의 도착작업장 구분이 자CY이고 EMPTY인 경우 수입본선 자CY_E 작업경로를 선택하여야 합니다.
                        return false;
                    }
                }
            }
        } else if (rowObj.arvWrkPlClsCd == SdConstants.WRK_PL_CLS_CD_OTHRCY) {
            // 도착작업장 구분이 타CY인 경우
            // 선택된 작업경로가 타CY 인지 확인
            for (let item of matched) {
                if (item.stdWrkPathNo != SdConstants.IMP_CVSSL_UCOM_CY_PATH) {
                    $c.gus.cfAlertMsg(scwin.DMessage["I0115"]);	// 해당 컨테이너의 도착작업장 구분이 타CY인 경우 수입본선 타CY 작업경로를 선택하여야 합니다.
                    return false;
                }
            }
        }
    } else if (hid_odrKndCd.getValue() == DsConstants.ODR_KND_CD_EXP_CVSSL_CNTR_ODR) {
        // 수출본선오더의 경우 확인
        // 작업경로 확인
        if (rowObj.dptWrkPlCd == rowObj.arvWrkPlCd) {
            // 출발작업장과 도착작업장이 동일한 경우
            // 선택된 작업경로가 직반입인지 확인
            for (let item of matched) {
                if (item.stdWrkPathNo != SdConstants.EXP_CVSSL_DRT_WRK_CRRYIN_PATH) {
                    $c.gus.cfAlertMsg(scwin.DMessage["I0109"]);	// 해당 컨테이너의 출발작업장과과 도착작업장이 동일하기 때문에 직반입 작업경로를 선택하여야 합니다.
                    return false;
                }
            }
        } else if (rowObj.dptWrkPlCd != rowObj.arvWrkPlCd && rowObj.dptWrkPlClsCd == SdConstants.WRK_PL_CLS_CD_PIER) {
            // 출발작업장 구분이 부두인 경우
            // 선택된 작업경로가 부두인지 확인
            for (let item of matched) {
                if (item.stdWrkPathNo != SdConstants.EXP_CVSSL_PIER) {
                    $c.gus.cfAlertMsg(scwin.DMessage["I0110"]);	// 해당 컨테이너의 출발작업장 구분이 부두인 경우 수출본선 부두 작업경로를 선택하여야 합니다.
                    return false;
                }
            }
        } else if (rowObj.dptWrkPlClsCd == SdConstants.WRK_PL_CLS_CD_CY) {
            // 출발작업장 구분이 자CY인 경우
            if (rowObj.fullEmptyClsCd == DsConstants.CNTR_FULL_EMPTY_CLS_CD_FULL) {
                // 해당 컨테이너가 FULL 인 경우
                // 선택된 작업경로가 자CY 인지 확인
                for (let item of matched) {
                    if (item.stdWrkPathNo == SdConstants.EXP_CVSSL_SHUTTLE_PATH) {
                        return true;	// 선택된 작업경로가 셔틀 경로인 경우 제외
                    } else if (item.stdWrkPathNo != SdConstants.EXP_CVSSL_MCOM_CY_PATH) {
                        $c.gus.cfAlertMsg(scwin.DMessage["I0112"]);	// 해당 컨테이너의 출발작업장 구분이 자CY이고 FULL인 경우 수출본선 자CY 작업경로를 선택하여야 합니다.
                        return false;
                    }
                }
            } else if (rowObj.fullEmptyClsCd == DsConstants.CNTR_FULL_EMPTY_CLS_CD_EMPTY) {
                // 해당 컨테이너가 EMPTY 인 경우
                // 선택된 작업경로가 자CY_E 인지 확인
                for (let item of matched) {
                    if (item.stdWrkPathNo == SdConstants.EXP_CVSSL_SHUTTLE_PATH) {
                        return true;	// 선택된 작업경로가 셔틀 경로인 경우 제외
                    } else if (item.stdWrkPathNo != SdConstants.EXP_CVSSL_MCOM_CY_EMPTY_PATH) {
                        $c.gus.cfAlertMsg(scwin.DMessage["I0114"]);	// 해당 컨테이너의 출발작업장 구분이 자CY이고 EMPTY인 경우 수출본선 자CY_E 작업경로를 선택하여야 합니다.
                        return false;
                    }
                }
            }
        } else if (rowObj.dptWrkPlClsCd == SdConstants.WRK_PL_CLS_CD_OTHRCY) {
            // 출발작업장 구분이 타CY인 경우
            // 선택된 작업경로가 타CY 인지 확인
            for (let item of matched) {
                if (item.stdWrkPathNo != SdConstants.EXP_CVSSL_UCOM_CY_PATH) {
                    $c.gus.cfAlertMsg(scwin.DMessage["I0116"]);	// 해당 컨테이너의 출발작업장 구분이 타CY인 경우 수출본선 타CY 작업경로를 선택하여야 합니다.
                    return false;
                }
            }
        }
    }

    return true;
};

/**
 * method
 * @name f_setOdrWorkStepWorkLobranInternalSellLodept
 * @description
 *  작업단계별 작업점소, 매출귀속부서 설정
 *  1. 운송모드
 *      1.1. 기준
 *          1.1.1. 작업점소 : 오더등록자의 소속점소
 *          1.1.2. 매출귀속부서 : 오더등록자의 소속점소의 운송부서
 *      1.2. 예외
 *          1.2.1. 작업점소 : 철송 도착역, 해송의 도착 해송부두 이후는 해당 작업장의 상위 작업장의 소속점소
 *          1.2.2. 매출귀속부서 : 설정된 작업장 소속점소의 운송부서
 *          1.2.3. 사용자 040239 (채태종) 의 경우 운송 부서를 4A5(인천제강운송)으로 설정
 *  2. 작업노드
 *      2.1. 기준
 *          2.1.1. 작업점소 : 작업장의 소속점소
 *          2.1.2. 매출귀속부서 : 설정된 작업점소의 보관부서, 단 부두의 경우 설정된 작업점소의 하역부서
 *      2.2. 예외
 *          2.2.1. 작업점소 : 철송역, 해송부두는 상위 작업단계(운송)의 작업점소
 *          2.2.2. 매출귀속부서 : 설정된 작업점소의 운송부서
 */
scwin.f_setOdrWorkStepWorkLobranInternalSellLodept = async function (row) {
    let rowObj = ds_odrWrkPathStepDetail.getRowJSON(row);
    if ($c.gus.cfIsNull(rowObj.wrkPlClsCd.trim())) {
        // 운송모드인 경우
        if ($c.gus.cfIsNull(rowObj.wrkLobranCd) || row > scwin.wrkLobranCdRow) {
            // 작업점소설정
            ds_odrWrkPathStepDetail.setCellData(row, "wrkLobranCd", scwin.wrkLobranCd);
            ds_odrWrkPathStepDetail.setCellData(row, "wrkLobranNm", scwin.wrkLobranNm);
            ds_odrWrkPathStepDetail.setCellData(row, "wrkLobranNmOrg", scwin.wrkLobranNm);

            // 매출귀속부서 설정
            ds_odrWrkPathStepDetail.setCellData(row, "internalSellLodeptCd", scwin.internalSellLodeptCd);
            ds_odrWrkPathStepDetail.setCellData(row, "internalSellLodeptNm", scwin.internalSellLodeptNm);
            ds_odrWrkPathStepDetail.setCellData(row, "internalSellLodeptNmOrg", scwin.internalSellLodeptNm);
        }
    } else {
        // 작업노드인 경우 - 무매출이 아닌경우만 설정
        if (rowObj.selpchItemCd.trim() != SdConstants.SELPCH_ITEM_CD_NOSELL) {
            if (rowObj.wrkPlClsCd == SdConstants.WRK_PL_CLS_CD_RAILSTN) {
                // 작업장 구분이 철도역인 경우인 경우

                // 작업점소설정
                ds_odrWrkPathStepDetail.setCellData(row, "wrkLobranCd", ds_odrWrkPathStepDetail.getCellData(row - 1, "wrkLobranCd"));
                ds_odrWrkPathStepDetail.setCellData(row, "wrkLobranNm", ds_odrWrkPathStepDetail.getCellData(row - 1, "wrkLobranNm"));
                ds_odrWrkPathStepDetail.setCellData(row, "wrkLobranNmOrg", ds_odrWrkPathStepDetail.getCellData(row - 1, "wrkLobranNmOrg"));

                // 매출귀속부서 설정
                ds_odrWrkPathStepDetail.setCellData(row, "internalSellLodeptCd", ds_odrWrkPathStepDetail.getCellData(row - 1, "internalSellLodeptCd"));
                ds_odrWrkPathStepDetail.setCellData(row, "internalSellLodeptNm", ds_odrWrkPathStepDetail.getCellData(row - 1, "internalSellLodeptNm"));
                ds_odrWrkPathStepDetail.setCellData(row, "internalSellLodeptNmOrg", ds_odrWrkPathStepDetail.getCellData(row - 1, "internalSellLodeptNmOrg"));

                if (ds_odrWrkPathStepDetail.getCellData(row - 1, "wrkStpCd") == DsConstants.WRK_STP_CD_RAILROAD) {
                    // 이전 단계가 철송인 경우 해당 작업장(철도역)의 소속점소로 작업점소 변경 매출부서 설정
                    let pCode = rowObj.dptWrkPlCd;
                    let pWrkPlClsCd = rowObj.wrkPlClsCd;
                    let pBizDomCd = SdConstants.BIZ_DOM_CD_TRANS;	// 사업영역코드 - 운송(120)

                    if ($c.gus.cfIsNull(pCode)) {
                        return;
                    }

                    let rtnList = await scwin.f_setWorkPlaceLobranCd(pCode, '', pBizDomCd, pWrkPlClsCd);
                    scwin.udc_workPlaceLobranCd_popup_callback1(row, rtnList);
                }
            } else if (rowObj.wrkPlClsCd == SdConstants.WRK_PL_CLS_CD_MARTRPIER) {
                // 작업장 구분이 해송부두인 경우

                // 작업점소설정
                ds_odrWrkPathStepDetail.setCellData(row, "wrkLobranCd", ds_odrWrkPathStepDetail.getCellData(row - 1, "wrkLobranCd"));
                ds_odrWrkPathStepDetail.setCellData(row, "wrkLobranNm", ds_odrWrkPathStepDetail.getCellData(row - 1, "wrkLobranNm"));
                ds_odrWrkPathStepDetail.setCellData(row, "wrkLobranNmOrg", ds_odrWrkPathStepDetail.getCellData(row - 1, "wrkLobranNmOrg"));

                // 매출귀속부서 설정
                ds_odrWrkPathStepDetail.setCellData(row, "internalSellLodeptCd", ds_odrWrkPathStepDetail.getCellData(row - 1, "internalSellLodeptCd"));
                ds_odrWrkPathStepDetail.setCellData(row, "internalSellLodeptNm", ds_odrWrkPathStepDetail.getCellData(row - 1, "internalSellLodeptNm"));
                ds_odrWrkPathStepDetail.setCellData(row, "internalSellLodeptNmOrg", ds_odrWrkPathStepDetail.getCellData(row - 1, "internalSellLodeptNmOrg"));

                if (ds_odrWrkPathStepDetail.getCellData(row - 1, "wrkStpCd") == DsConstants.WRK_STP_CD_MARTR) {
                    // 이전 단계가 해송인 경우 해당 작업장(해송부두)의 소속점소로 작업점소 변경 매출부서 설정
                    let pCode = rowObj.dptWrkPlCd;
                    let pWrkPlClsCd = rowObj.wrkPlClsCd;
                    let pBizDomCd = SdConstants.BIZ_DOM_CD_TRANS;	// 사업영역코드 - 운송(120)

                    if ($c.gus.cfIsNull(pCode)) {
                        return;
                    }

                    let rtnList = await scwin.f_setWorkPlaceLobranCd(pCode, '', pBizDomCd, pWrkPlClsCd);
                    scwin.udc_workPlaceLobranCd_popup_callback1(row, rtnList);
                }
            } else {
                // 기타 작업노드인 경우
                if (rowObj.wrkPlClsCd == SdConstants.WRK_PL_CLS_CD_PIER) {
                    // 작업장구분이 부두인 경우
                    let pCode = rowObj.dptWrkPlCd;
                    let pName = rowObj.dptWrkPlNm;
                    let pOrgName = ds_odrWrkPathStepDetail.getOriginalCellData(row, "dptWrkPlNm");
                    let pWrkPlClsCd = rowObj.wrkPlClsCd;
                    let pBizDomCd = SdConstants.BIZ_DOM_CD_STV;	// 사업영역코드 - 하역(110)
                    let pWrkLobranCd = ds_odrWrkPathStepDetail.getCellData(row, "wrkLobranCd");
                    let pInternalSellLodeptCd = ds_odrWrkPathStepDetail.getCellData(row, "internalSellLodeptCd");
                    if ($c.gus.cfIsNull(pCode)) {
                        return;
                    }
                    if ($c.gus.cfIsNull(pWrkLobranCd) || $c.gus.cfIsNull(pInternalSellLodeptCd)) {
                        let rtnList = await scwin.f_setWorkPlaceLobranCd(pCode, '', pBizDomCd, pWrkPlClsCd);
                        scwin.udc_workPlaceLobranCd_popup_callback2(row, rtnList);
                    } else if (pName != pOrgName) {
                        let rtnList = await scwin.f_setWorkPlaceLobranCd(pCode, '', pBizDomCd, pWrkPlClsCd);
                        scwin.udc_workPlaceLobranCd_popup_callback2(row, rtnList);
                    }
                } else {
                    // 기타 작업장인 경우
                    let pCode = rowObj.dptWrkPlCd;
                    let pName = rowObj.dptWrkPlNm;
                    let pOrgName = ds_odrWrkPathStepDetail.getOriginalCellData(row, "dptWrkPlNm");
                    let pWrkPlClsCd = rowObj.wrkPlClsCd;
                    let pBizDomCd = SdConstants.BIZ_DOM_CD_STR;	// 사업영역코드 - 보관(130)
                    let pWrkLobranCd = ds_odrWrkPathStepDetail.getCellData(row, "wrkLobranCd");
                    let pInternalSellLodeptCd = ds_odrWrkPathStepDetail.getCellData(row, "internalSellLodeptCd");

                    if ($c.gus.cfIsNull(pCode)) {
                        return;
                    }
                    if ($c.gus.cfIsNull(pWrkLobranCd) || $c.gus.cfIsNull(pInternalSellLodeptCd)) {
                        let rtnList = await scwin.f_setWorkPlaceLobranCd(pCode, '', pBizDomCd, pWrkPlClsCd);
                        scwin.udc_workPlaceLobranCd_popup_callback2(row, rtnList);
                    } else if (pName != pOrgName) {
                        let rtnList = await scwin.f_setWorkPlaceLobranCd(pCode, '', pBizDomCd, pWrkPlClsCd);
                        scwin.udc_workPlaceLobranCd_popup_callback2(row, rtnList);
                    }
                }
            }
        } else {
            if (rowObj.wrkPlClsCd == SdConstants.WRK_PL_CLS_CD_RAILSTN && ds_odrWrkPathStepDetail.getCellData(row - 1, "wrkStpCd") == DsConstants.WRK_STP_CD_RAILROAD) {
                // 작업장 구분이 철도역이고,이전 단계가 철송인 경우 해당 작업장(철도역)의 소속점소로 작업점소 변경 매출부서 설정

                let pCode = rowObj.dptWrkPlCd;
                let pWrkPlClsCd = rowObj.wrkPlClsCd;
                let pBizDomCd = SdConstants.BIZ_DOM_CD_TRANS;	// 사업영역코드 - 운송(120)

                if ($c.gus.cfIsNull(pCode)) {
                    return;
                }
                let rtnList = await scwin.f_setWorkPlaceLobranCd(pCode, '', pBizDomCd, pWrkPlClsCd);
                scwin.udc_workPlaceLobranCd_popup_callback1(row, rtnList);
            } else if (rowObj.wrkPlClsCd == SdConstants.WRK_PL_CLS_CD_MARTRPIER && ds_odrWrkPathStepDetail.getCellData(row - 1, "wrkStpCd") == DsConstants.WRK_STP_CD_MARTR) {
                // 작업장 구분이 해송부두이고,이전 단계가 해송인 경우 해당 작업장(해송부두)의 소속점소로 작업점소 변경 매출부서 설정

                let pCode = rowObj.dptWrkPlCd;
                let pWrkPlClsCd = rowObj.wrkPlClsCd;
                let pBizDomCd = SdConstants.BIZ_DOM_CD_TRANS;	// 사업영역코드 - 운송(120)

                if ($c.gus.cfIsNull(pCode)) {
                    return;
                }

                let rtnList = await scwin.f_setWorkPlaceLobranCd(pCode, '', pBizDomCd, pWrkPlClsCd);
                scwin.udc_workPlaceLobranCd_popup_callback1(row, rtnList);
            }
        }
    }

    ds_odrWrkPathStepDetail.modifyAllStatus("R");
};

/**
 * method
 * @name f_setWorkPlaceLobranCd
 * @params {String} pCode   코드
 * @params {String} pName   코드명
 * @params {String} pBizDomCd
 * @params {String} pWrkPlClsCd
 * @params {Function}   callbackFunc
 * @description 작업장 정보를 조회한다.
 */
scwin.f_setWorkPlaceLobranCd = async function (pCode, pName, pBizDomCd, pWrkPlClsCd) {
    // 조회조건이 아닌경우 종료
    if ($c.gus.cfIsNull(pCode) && $c.gus.cfIsNull(pBizDomCd)) {
        return false;
    }

    let pWhere = pWrkPlClsCd + "," + pBizDomCd;
    return udc_workPlaceLobranCd.cfCommonPopUpAsync(null
        , pCode					// 화면에서의 ??? Code Element의	Value
        , pName					// 화면에서의 ??? Name Element의	Value
        , "T"					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
        , null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
        , null					// Title순서
        , null					// 보여주는 각 컬럼들의 폭
        , null					// 컬럼중에서 숨기는	컬럼 지정
        , pWhere					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
        , null					// POP-UP뛰을때 원도우의	사용자 정의	폭
        , null					// POP-UP뛰을때 우도우의	사용자 정의	높이
        , null					// 윈도우 위치 Y좌표
        , null					// 윈도우 위치 X좌표
        , null					// 중복체크여부	("F")
        , "F"					// 전체검색허용여부	("F")
        , "작업장,작업장코드,작업장명"				// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
        , "T"			// Data건수가 0건일때 Window를 뛰우지 않음 리턴 : "N/A" 또는 null
        , null
    );
};

/**
 * method
 * @name udc_workPlaceLobranCd_popup_callback1
 * @description 작업장 정보를 조회팝업 콜백1
 */
scwin.udc_workPlaceLobranCd_popup_callback1 = function (row, rtnList) {
    if (rtnList != null) {
        if (rtnList[0].trim() != "N/A") {
            //return value Assign

            // 작업점소설정
            scwin.wrkLobranCd = rtnList[2];	// 작업장의 소속물류점소코드
            scwin.wrkLobranNm = rtnList[3];	// 작업장의 소속물류점소명

            // 매출귀속부서 설정
            scwin.internalSellLodeptCd = rtnList[4];	// 소속물류점소 보관부서코드
            scwin.internalSellLodeptNm = rtnList[5];	// 소속물류점소 보관부서명

            // 철도역/해송부두 단계 Row 설정
            scwin.wrkLobranCdRow = row;
        }
    }
};

/**
 * method
 * @name udc_workPlaceLobranCd_popup_callback2
 * @description 작업장 정보를 조회팝업 콜백2
 */
scwin.udc_workPlaceLobranCd_popup_callback2 = function (row, rtnList) {
    if (rtnList != null) {
        if (rtnList[0].trim() != "N/A") {
            //return value Assign
            // 출발작업장 설정
            ds_odrWrkPathStepDetail.setCellData(row, "dptWrkPlCd", rtnList[0]);	// 작업장코드 <- 출발작업장코드
            ds_odrWrkPathStepDetail.setCellData(row, "dptWrkPlNm", rtnList[1]);	// 작업장명 < - 출발작업장명

            // 작업점소설정
            ds_odrWrkPathStepDetail.setCellData(row, "wrkLobranCd", rtnList[2]);	// 작업장의 소속물류점소코드
            ds_odrWrkPathStepDetail.setOriginalCellData(row, "wrkLobranNm", rtnList[3]);	// 작업장의 소속물류점소명
            ds_odrWrkPathStepDetail.setCellData(row, "wrkLobranNm", rtnList[3]);	// 작업장의 소속물류점소명

            // 매출귀속부서 설정
            ds_odrWrkPathStepDetail.setCellData(row, "internalSellLodeptCd", rtnList[4]);	// 소속물류점소 보관부서코드
            ds_odrWrkPathStepDetail.setOriginalCellData(row, "internalSellLodeptNm", rtnList[5]);	// 소속물류점소 보관부서명
            ds_odrWrkPathStepDetail.setCellData(row, "internalSellLodeptNm", rtnList[5]);	// 소속물류점소 보관부서명
        }
    }
};

/**
 * event
 * @name sbm_save_submitdone
 * @description
 */
scwin.sbm_save_submitdone = async function (e) {//TODO submitdone 이벤트 삭제해야됨?
    if (e.responseJSON?.resultDataSet?.length && e.responseJSON.resultDataSet[0].Code == -1) {
        $c.gus.cfDisableBtnOnly([btnUpdate]);
        $c.gus.cfEnableBtnOnly([btnSave]);
    } else {
        await $c.gus.cfAlertMsg(MSG_CM_INF_001);	// 성공적으로 저장하였습니다.
        await scwin.f_Retrieve();
    }
};

/**
 * event
 * @name sbm_retrieve_submitdone
 * @description
 */
scwin.sbm_retrieve_submitdone = async function (e) {
    if (e.responseJSON?.resultDataSet?.length && e.responseJSON.resultDataSet[0].Code == -1) {
        tbx_totalRows.setValue("0");
        return;
    }

    let rowCnt = ds_odrCntrWrkPath.getRowCount();
    tbx_totalRows.setValue(rowCnt);
    if (ds_order.getRowCount() && rowCnt == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
    }
    if (rowCnt) {
        gr_odrCntrWrkPath.setFocusedCell(0, gr_odrCntrWrkPath.getFocusedColumnIndex() ?? 1, false);
    }

    hid_chkUseFilter.setValue("true");

    gr_odrCntrWrkPath.setReadOnly("grid", true);
    scwin.setGrOdrWrkPathStepDetailReadonly(true);

    if (ds_order.getCellData(0, "odrDcsnYn") != DsConstants.YN_YES) {
        $c.gus.cfEnableBtnOnly([btnUpdate]);
        $c.gus.cfDisableBtnOnly([btnSave]);
    } else {
        $c.gus.cfEnableBtnOnly([btnUpdate]);
        $c.gus.cfDisableBtnOnly([btnSave]);
        scwin.f_chkContainerWorkPath();
    }

    if (ds_order.getCellData(0, "odrCompleteYn") != DsConstants.YN_YES) {
        $c.gus.cfEnableBtnOnly([btnUpdate]);
        $c.gus.cfDisableBtnOnly([btnSave]);
        scwin.f_chkContainerWorkPath();
    } else {
        $c.gus.cfDisableBtnOnly([btnUpdate, btnSave]);
    }

    if (ds_odrCntrWrkPath.getRowCount() > 0 && ds_order.getCellData(0, "odrDcsnYn") != DsConstants.YN_YES && ds_order.getCellData(0, "odrCompleteYn") != DsConstants.YN_YES) {
        // 작업경로가 저장되지 않은 경우 수정모드로 설정
        if (ds_odrCntrWrkPath.getCellData(0, "odrWrkPathSeq") == 0) {
            scwin.f_Update();
        }
    }

    $c.gus.cfDisableBtnOnly([btnInsertRow, btnDeleteRow, btnUndoMark]);

    scwin.f_setTabOrderInfo(dma_orderSearch.get("odrNo"));

    if (ds_order.getCellData(0, "odrDcsnYn") != DsConstants.YN_YES && ds_odrWrkPathStep.getRowCount() > 0) {
        let tab2_hid_chkReterieve = $p.parent().tab_mxTab_page.getFrame(0).getObj("hid_chkReterieve");
        if (typeof tab2_hid_chkReterieve?.setValue === "function") {
            tab2_hid_chkReterieve.setValue("");	// 재조회 - 작업경로
        }
    }

    hid_chkReterieve.setValue("retrieveIn");	// 조회 성공여부

    let v_odrWrkPathCnt = ds_order.getCellData(0, "odrWrkPathCnt");
    if (v_odrWrkPathCnt > 0 && v_odrWrkPathCnt >= ds_odrCntrWrkPath.getRowCount()) {
        // 작업경로가 지정된 경우
        if (ds_order.getCellData(0, "odrDcsnYn") != DsConstants.YN_YES) {
            // 오더가 확정되지 않은 경우
            dscommon.cf_ShowObject([btnConfirmOrder]);
            $c.gus.cfEnableObjects([btnConfirmOrder]);
        } else {
            // 오더가 확정된 경우
            $c.gus.cfDisableObjects([btnConfirmOrder]);

            if (ds_order.getCellData(0, "odrCompleteYn") == DsConstants.YN_YES) {
                $c.gus.cfDisableBtnOnly([btnUpdate]);
            }
        }
    } else {
        // 작업경로가 지정되지 않은 경우
        dscommon.cf_ShowObject([btnConfirmOrder]);
        $c.gus.cfDisableObjects([btnConfirmOrder]);
    }

    // 자동오더인 경우 수정 할수 없음.
    if (ds_order.getCellData(0, "autoOdrYn") == DsConstants.YN_YES) {
        $c.gus.cfDisableBtnOnly([btnUpdate, btnSave]);
    }
};

