/**
 * event
 * @name ds_order_ondataload
 * @description
 */
scwin.ds_order_ondataload = async function () {

    let rowCnt = ds_order.getRowCount();
    if (rowCnt == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_003, new Array("조회결과"));

        scwin.f_FieldClear();

        // 오더정보 초기화
        tbx_realMchtclntNm.setValue("");
        tbx_ctrtClntNm.setValue("");
        tbx_ctrtNo.setValue("");
        tbx_odrKndNm.setValue("");
    } else {
        // 오더 종류가 내수운송인 경우 수요가로 명칭 변환
        if (ds_order.getCellData(0, "odrKndCd").charAt(0) == SdConstants.WRK_PL_CLS_CD_DOOR) {
            tbx_realMchtClntNmLbl.setValue("수요가");
            // 수요가명 설정
            tbx_realMchtclntNm.setValue(ds_order.getCellData(0, "dmndNm"));
            // 수요가 코드 설정
            hid_realMchtclntNo.setValue(ds_order.getCellData(0, "dmndNo"));
        } else {
            tbx_realMchtClntNmLbl.setValue("실화주");
            // 실화주명 설정
            tbx_realMchtclntNm.setValue(ds_order.getCellData(0, "realMchtClntNm"));
            // 실화주 코드 설정
            hid_realMchtclntNo.setValue(ds_order.getCellData(0, "realMchtClntNo"));
        }
        scwin.f_setDisplayOdrKndCd(ds_order.getCellData(0, "odrKndCd"));

        // 계약거래처명 설정
        tbx_ctrtClntNm.setValue(ds_order.getCellData(0, "ctrtClntNm"));
        // 계약번호 설정
        tbx_ctrtNo.setValue(ds_order.getCellData(0, "ctrtNo"));
        // 오더종류명 설정
        tbx_odrKndNm.setValue(ds_order.getCellData(0, "odrKndNm"));

        // 계약거래처 코드 설정
        hid_ctrtClntNo.setValue(ds_order.getCellData(0, "ctrtClntNo"));
        // 계약번호 설정
        hid_ctrtNo.setValue(ds_order.getCellData(0, "ctrtNo"));
        // 오더종류코드 설정
        hid_odrKndCd.setValue(ds_order.getCellData(0, "odrKndCd"));

        if (ds_order.getCellData(0, "odrDelYn") == DsConstants.YN_YES) {
            gr_odrCntrWrkPath.setReadOnly("grid", true);
            scwin.setGrOdrWrkPathStepDetailReadonly(true);
            $c.gus.cfDisableBtnOnly([btnInsertRow, btnDeleteRow, btnUndoMark]);
        } else {
            gr_odrCntrWrkPath.setReadOnly("grid", false);
            scwin.setGrOdrWrkPathStepDetailReadonly(false);
            $c.gus.cfEnableBtnOnly([btnInsertRow, btnDeleteRow, btnUndoMark]);
        }
    }
};

/** //TODO
 * event
 * @name ds_odrCommodity_ondataload
 * @description
 */
scwin.ds_odrCommodity_ondataload = function () {

    return;
    let rowCnt = ds_odrCommodity.getRowCount();
    if (!rowCnt) {
        return;
    }
    for (let i = 0; i < rowCnt; i++) {
        ds_odrCntrSummary.AddRow();
        ds_odrCntrSummary.setCellData(ds_odrCntrSummary.getRowPosition(), "odrNo", ds_odrCommodity.getCellData(i, "odrNo"));	// 오더번호
        ds_odrCntrSummary.setCellData(ds_odrCntrSummary.getRowPosition(), "cntrNo", ds_odrCommodity.getCellData(i, "cntrNo"));	// 컨테이너번호
        ds_odrCntrSummary.setCellData(ds_odrCntrSummary.getRowPosition(), "cntrSizCd", ds_odrCommodity.getCellData(i, "cntrSizCd"));	// 컨테이너SIZE코드
        ds_odrCntrSummary.setCellData(ds_odrCntrSummary.getRowPosition(), "cntrTypCd", ds_odrCommodity.getCellData(i, "cntrTypCd"));	// 컨테이너TYPE코드
        ds_odrCntrSummary.setCellData(ds_odrCntrSummary.getRowPosition(), "fullEmptyClsCd", ds_odrCommodity.getCellData(i, "fullEmptyClsCd"));	// FULLEMPTY구분코드
        ds_odrCntrSummary.setCellData(ds_odrCntrSummary.getRowPosition(), "qty", ds_odrCommodity.getCellData(i, "qty"));	// 수량
        ds_odrCntrSummary.setCellData(ds_odrCntrSummary.getRowPosition(), "wrkStDt", ds_odrCommodity.getCellData(i, "wrkStDt"));	// 작업시작일자
        ds_odrCntrSummary.setCellData(ds_odrCntrSummary.getRowPosition(), "wrkStHh", ds_odrCommodity.getCellData(i, "wrkStHh"));	// 작업시작시간
        ds_odrCntrSummary.setCellData(ds_odrCntrSummary.getRowPosition(), "wrkEndDt", ds_odrCommodity.getCellData(i, "wrkEndDt"));	// 작업종료일자
        ds_odrCntrSummary.setCellData(ds_odrCntrSummary.getRowPosition(), "wrkEndHh", ds_odrCommodity.getCellData(i, "wrkEndHh"));	// 작업종료시간
    }

    ds_odrCntrSummary.modifyAllStatus("R");
};

/**
 * event
 * @name gr_odrCntrWrkPath_onviewchange
 * @description
 */

scwin.gr_odrCntrWrkPath_onviewchange = async function (info) {
    const row = info.rowIndex;
    //for=ds_odrCntrWrkPath event=OnColumnChanged(row,colid)
    const colid = info.colId;
    let copyTempDataSet = false;
    if (colid == "ctrtWrkPathSeq") {
        // 이미 조회된 작업단계인지 확인
        scwin.setOdrWrkPathStepDetailColumnFilter();

        if (ds_odrCntrWrkPath.getCellData(row, "ctrtWrkPathSeq") > 0) {
            if (ds_odrWrkPathStepDetail.getRowCount()) {
                // 이미 조회된 작업단계
            } else {
                // 임시데이터셋에 존재하는 작업경로 정보와 동일한 정보인지 확인
                // 해당컨테이너의 출발작업장,도착작업장,F/E 가 모두 동일한 경우 임시 데이터셋에 저장된 작업단계를 복사한다.
                if (ds_odrCntrWrkPathTemp.getRowCount()) {

                    if (ds_odrCntrWrkPath.getCellData(row, "dptWrkPlCd") == ds_odrCntrWrkPathTemp.getCellData(ds_odrCntrWrkPathTemp.getRowPosition(), "dptWrkPlCd")
                        && ds_odrCntrWrkPath.getCellData(row, "arvWrkPlCd") == ds_odrCntrWrkPathTemp.getCellData(ds_odrCntrWrkPathTemp.getRowPosition(), "arvWrkPlCd")
                        && ds_odrCntrWrkPath.getCellData(row, "fullEmptyClsCd") == ds_odrCntrWrkPathTemp.getCellData(ds_odrCntrWrkPathTemp.getRowPosition(), "fullEmptyClsCd")) {

                        // 임시 데이터셋에 존재하는 작업경로인지 확인
                        scwin.setOdrWrkPathStepDetailTempColumnFilter();
                        if (ds_odrWrkPathStepDetailTemp.getRowCount()) {
                            scwin.f_CopyDataSetValue(ds_odrWrkPathStepDetailTemp, ds_odrWrkPathStepDetail);
                            copyTempDataSet = true;
                        }
                    }
                }

                if (!copyTempDataSet) {
                    // 작업단계 검색 조건 설정
                    dma_searchWrkStep.set("odrNo", ds_odrCntrWrkPath.getCellData(row, "odrNo"));
                    dma_searchWrkStep.set("cntrSeq", ds_odrCntrWrkPath.getCellData(row, "cntrSeq"));
                    dma_searchWrkStep.set("odrWrkPathSeq", ds_odrCntrWrkPath.getCellData(row, "odrWrkPathSeq"));
                    dma_searchWrkStep.set("ctrtNo", ds_odrCntrWrkPath.getCellData(row, "ctrtNo"));
                    dma_searchWrkStep.set("ctrtWrkPathSeq", ds_odrCntrWrkPath.getCellData(row, "ctrtWrkPathSeq"));

                    await scwin.f_RetrieveWorkStep();
                }
            }
        }

        tbx_totalRows2.setValue(ds_odrWrkPathStepDetail.getRowCount());

        scwin.f_checkWorkStepEditMode();
    }
};

/**
 * event
 * @name ds_odrCntrWrkPath_onbeforerowpositionchange
 * @description
 */
scwin.ds_odrCntrWrkPath_onbeforerowpositionchange = function (info) {
    //이 함수는 async 함수로 선언하면 안된다.
    if (gr_odrWrkPathStepDetail.getReadOnly("grid")) {
        return true;
    }

    // 수정모드일 경우
    // 작업경로별 작업단계 입력 데이터 필수항목 확인
    // 현재 품명의 작업단계 정보의  Vaildation 을 검사한다.
    if (!$c.gus.cfValidate([gr_odrWrkPathStepDetail])) {
        return false;
    }

    let rowObj = null;
    // 필수 입력 확인
    for (let idx = 0; idx < ds_odrWrkPathStepDetail.getRowCount(); idx++) {
        rowObj = ds_odrWrkPathStepDetail.getRowJSON(idx);
        if (ds_odrWrkPathStepDetail.getRowStatus(idx) == "D") {
            continue;
        }
        // RowStatus 가 Delete 가 아닌 경우
        // 작업장 확인 - 작업구분이 운송이 아닌 경우 작업장은 필수 입력 항목입니다.
        if (!$c.gus.cfIsNull(rowObj.wrkPlClsCd.trim()) && $c.gus.cfIsNull(rowObj.dptWrkPlCd.trim())) {
            $c.gus.cfAlertMsg("작업단계 [" + (idx + 1) + "]의 " + MSG_CM_WRN_007, new Array("작업장")).then(() => {
                gr_odrWrkPathStepDetail.setFocusedCell(idx, "dptWrkPlNm", true);
            });
            return false;
        }

        // 매출입항목이 무매출이 아니경우에는 작업점소, 매출귀속부서는 필수 입력항목입니다.
        if (rowObj.selpchItemCd != SdConstants.SELPCH_ITEM_CD_NOSELL) {
            // 작업점소 확인
            if ($c.gus.cfIsNull(rowObj.wrkLobranCd.trim())) {
                $c.gus.cfAlertMsg("작업단계 [" + (idx + 1) + "]의 " + MSG_CM_WRN_007, new Array("작업점소")).then(() => {
                    gr_odrWrkPathStepDetail.setFocusedCell(idx, "wrkLobranNm", true);
                });
                return false;
            }

            //매출귀속부서 확인
            if ($c.gus.cfIsNull(rowObj.internalSellLodeptCd.trim())) {
                $c.gus.cfAlertMsg("작업단계 [" + (idx + 1) + "]의 " + MSG_CM_WRN_007, new Array("매출귀속부서")).then(() => {
                    gr_odrWrkPathStepDetail.setFocusedCell(idx, "internalSellLodeptNm", true);
                });
                return false;
            }
        }
    }

    // 작업단계 정보가 정확하게 설정되었는지 확인
    if (!scwin.f_chkOdrWorkStepCanRowPosChange()) {
        return false;
    }
    return true;
};

/**
 * event
 * @name gr_odrCntrWrkPath_onrowindexchange
 * @description
 */
scwin.gr_odrCntrWrkPath_onrowindexchange = async function (row, oldRow) {
    //for=ds_odrCntrWrkPath event=OnRowPosChanged(row)
    ds_odrWrkPathStepDetail.setBroadcast(false, false);
    scwin.setOdrWrkPathStepDetailColumnFilter(true);

    if (ds_odrCntrWrkPath.getCellData(row, "ctrtWrkPathSeq") > 0) {
        if (ds_odrWrkPathStepDetail.getRowCount() > 0) {
            // 이미 작업단계가 존재함.
        } else {
            ds_odrWrkPathStepDetail.setBroadcast(true, true);
            // 작업단계 검색 조건 설정
            dma_searchWrkStep.set("odrNo", ds_odrCntrWrkPath.getCellData(row, "odrNo"));
            dma_searchWrkStep.set("cntrSeq", ds_odrCntrWrkPath.getCellData(row, "cntrSeq"));
            dma_searchWrkStep.set("odrWrkPathSeq", ds_odrCntrWrkPath.getCellData(row, "odrWrkPathSeq"));
            dma_searchWrkStep.set("ctrtNo", ds_odrCntrWrkPath.getCellData(row, "ctrtNo"));
            dma_searchWrkStep.set("ctrtWrkPathSeq", ds_odrCntrWrkPath.getCellData(row, "ctrtWrkPathSeq"));

            await scwin.f_RetrieveWorkStep();
        }
        tbx_totalRows2.setValue(ds_odrWrkPathStepDetail.getRowCount());
    }

    // 해당 품명의 실적 발생여부를 확인하여 수정 가능 항목을 설정한다.
    // 실적 발생시 수정할 수 없다.
    // 실적 발생여부를 조회하여 수정항목을 설정한다.
    if (row > 0 && btnUpdate.getDisabled()) {
        if (scwin.f_chkResultsConfirmationContainer(row)) {
            gr_odrCntrWrkPath.setReadOnly("grid", true);
            scwin.setGrOdrWrkPathStepDetailReadonly(true);
            $c.gus.cfDisableBtnOnly([btnInsertRow, btnDeleteRow, btnUndoMark]);
        } else {
            gr_odrCntrWrkPath.setReadOnly("grid", false);
            scwin.setGrOdrWrkPathStepDetailReadonly(false);
            $c.gus.cfEnableBtnOnly([btnInsertRow, btnDeleteRow, btnUndoMark]);
        }
    }

    scwin.f_checkWorkStepEditMode();

    scwin.wrkLobranCd = scwin.lobranCd;	// 작업점소코드
    scwin.wrkLobranNm = scwin.lobranNm;	// 작업점소명
    scwin.setInternalSellLodeptInfo(ds_lobran.getCellData(0, "lobranCd"), ds_lobran.getCellData(0, "lobranNm"));
    scwin.wrkLobranCdRow = 0;	// 작업점소 설정 ROW 초기화
    ds_odrWrkPathStepDetail.setBroadcast(true, true);
};

