/**
 * event
 * @name setOdrWrkPathStepDetailColumnFilter
 * @description
 */
scwin.setOdrWrkPathStepDetailColumnFilter = function (dontSetBroadcast = false) {
    if (!dontSetBroadcast) {
        ds_odrWrkPathStepDetail.setBroadcast(false, false);
    }
    ds_odrWrkPathStepDetail.clearFilter();
    if (hid_chkUseFilter.getValue() !== "true") {
        ds_odrWrkPathStepDetail.setBroadcast(true, true);
        return;
    }

    let v_odrNo = "";
    let v_cntrSeq = "0";
    let v_odrWrkPathSeq = "";
    let v_ctrtWrkPathSeq = "";
    let row = gr_odrCntrWrkPath.getFocusedRowIndex();
    // Filter 적용을 위한 값
    if (row >= 0) {
        let rowObj = ds_odrCntrWrkPath.getRowJSON(row);
        v_odrNo = rowObj.odrNo;
        v_cntrSeq = rowObj.cntrSeq;
        v_odrWrkPathSeq = rowObj.odrWrkPathSeq;
        v_ctrtWrkPathSeq = rowObj.ctrtWrkPathSeq;
    }
    // 필터 적용
    ds_odrWrkPathStepDetail.setColumnFilter({ type: 'row', colIndex: 'odrNo', key: v_odrNo, condition: 'and', exactMatch: true });
    ds_odrWrkPathStepDetail.setColumnFilter({ type: 'row', colIndex: 'cntrSeq', key: v_cntrSeq, condition: 'and', exactMatch: true });
    ds_odrWrkPathStepDetail.setColumnFilter({ type: 'row', colIndex: 'odrWrkPathSeq', key: v_odrWrkPathSeq, condition: 'and', exactMatch: true });
    ds_odrWrkPathStepDetail.setColumnFilter({ type: 'row', colIndex: 'ctrtWrkPathSeq', key: v_ctrtWrkPathSeq, condition: 'and', exactMatch: true });
    scwin.setOdrWrkPathStepDetailMultisortTimeout(0, dontSetBroadcast);
};

