/**
 * method
 * @name setLkStepNoColumnFilter
 * @description
 */
scwin.setLkStepNoColumnFilter = function (row, dltObj) {
    if (row === undefined) {
        row = gr_odrWrkPathStepDetail.getFocusedRowIndex();
    }
    if (dltObj === undefined) {
        dltObj = ds_LkStepNo;
    }
    dltObj.clearFilter();
    if (!ds_odrWrkPathStepDetail.getRowCount() || row < 0) {
        return;
    };
    let rowObj = ds_odrWrkPathStepDetail.getRowJSON(row);
    let v_wrkPlClsCd = rowObj.wrkPlClsCd.trim();
    let v_fltrCd1 = "";

    // 작업장구분 코드로 FLTR_CD_1 값 조회
    if (v_wrkPlClsCd != "") {
        let matched = ds_wrkPlClsCd.getMatchedJSON("cd", v_wrkPlClsCd, true);
        if (matched.length) {
            v_fltrCd1 = matched[matched.length - 1].fltrCd1;
        }
    }

    let v_key = "02";   // 운송 (작업단계코드 : 02)
    if (v_fltrCd1 == "02") {	// 하역 (작업단계코드 : 01)
        v_key = "01";
    } else if (v_fltrCd1 != "") {	// 본관,포장 (작업단계코드 : 03,04)
        v_key = "03";
    }
    dltObj.setColumnFilter({ type: 'row', colIndex: 'topWrkStpCd', key: v_key, condition: 'and', exactMatch: true });
};

/**
 * method
 * @name setLkStepNoChkColumnFilter
 * @description
 */
scwin.setLkStepNoChkColumnFilter = function (row) {
    scwin.setLkStepNoColumnFilter(row, ds_LkStepNoChk);
    // 작업장구분에 따른 작업단계정보 확인
    if (row < 0) {
        return;
    }

    let matched = ds_LkStepNoChk.getMatchedIndex("wrkStpCd", ds_odrWrkPathStepDetail.getCellData(row, "wrkStpCd"), true);
    if (!matched.length) {
        ds_odrWrkPathStepDetail.setCellData(row, "wrkStpCd", "");
    }
};

